use anyhow::Result;

use crate::db::Database;
use crate::issue_file::validate_comment_kind;
use crate::shared_writer::SharedWriter;
use crate::utils::format_issue_id;

pub fn run(
    db: &Database,
    writer: Option<&SharedWriter>,
    issue_id: i64,
    content: &str,
    kind: &str,
) -> Result<()> {
    if !validate_comment_kind(kind) {
        eprintln!("Warning: unknown comment kind '{}'. Known kinds: note, plan, decision, observation, blocker, resolution, result, handoff, human", kind);
    }
    db.require_issue(issue_id)?;
    if let Some(w) = writer {
        w.add_comment(db, issue_id, content, kind)?;
    } else {
        db.add_comment(issue_id, content, kind)?;
    }
    println!("Added comment to issue {}", format_issue_id(issue_id));
    Ok(())
}

