use anyhow::Result;
use std::path::Path;

use crate::db::Database;

/// `crosslink compact` — run event compaction manually.
pub fn run(crosslink_dir: &Path, db: &Database, force: bool) -> Result<()> {
    let sync = crate::sync::SyncManager::new(crosslink_dir)?;
    sync.init_cache()?;
    sync.fetch()?;
    let cache_dir = sync.cache_path().to_path_buf();

    // Load agent config for agent_id
    let agent = crate::identity::AgentConfig::load(crosslink_dir)?
        .ok_or_else(|| anyhow::anyhow!("No agent configured. Run 'crosslink agent init' first."))?;

    match crate::compaction::compact(&cache_dir, &agent.agent_id, force)? {
        Some(result) => {
            println!("Compaction complete.");
            if result.events_processed > 0 {
                println!(
                    "  Events processed: {}, issues updated: {}, locks updated: {}",
                    result.events_processed, result.issues_materialized, result.locks_materialized
                );
            } else {
                println!("  No new events to process.");
            }
            if result.skew_warnings > 0 {
                eprintln!(
                    "  Warning: {} event clock skew warning(s) detected during compaction",
                    result.skew_warnings
                );
            }
            if result.unsigned_warnings > 0 {
                eprintln!(
                    "  Warning: {} unsigned event(s) detected during compaction",
                    result.unsigned_warnings
                );
            }
            if result.git_skew_violations > 0 {
                eprintln!(
                    "  Warning: {} clock skew violation(s) detected (see checkpoint/skew_warnings.json)",
                    result.git_skew_violations
                );
                let violations =
                    crate::clock_skew::read_skew_violations(&cache_dir).unwrap_or_default();
                for v in &violations {
                    eprintln!(
                        "    - agent={}, skew={}s, event={}, event_ts={}, commit_ts={}",
                        v.agent_id,
                        v.skew_seconds,
                        v.event_description,
                        v.event_timestamp.to_rfc3339(),
                        v.commit_timestamp.to_rfc3339()
                    );
                }
            }
        }
        None => {
            println!("Compaction skipped: lease held by another agent. Use --force to override.");
        }
    }

    // Re-hydrate after compaction
    crate::hydration::hydrate_to_sqlite(&cache_dir, db)?;
    Ok(())
}

use anyhow::{bail, Context, Result};
use std::fs;
use std::path::Path;

use crate::commands::init;
use crate::ConfigCommands;

// ---------------------------------------------------------------------------
// Config key registry
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Copy)]
enum ConfigType {
    Bool,
    Enum(&'static [&'static str]),
    String,
    StringArray,
}

struct ConfigKey {
    key: &'static str,
    config_type: ConfigType,
    description: &'static str,
}

static REGISTRY: &[ConfigKey] = &[
    ConfigKey {
        key: "tracking_mode",
        config_type: ConfigType::Enum(&["strict", "normal", "relaxed"]),
        description: "How aggressively issue tracking is enforced before code changes",
    },
    ConfigKey {
        key: "intervention_tracking",
        config_type: ConfigType::Bool,
        description: "Log driver interventions for autonomy improvement",
    },
    ConfigKey {
        key: "cpitd_auto_install",
        config_type: ConfigType::Bool,
        description: "Automatically install cpitd (context-provider) during init",
    },
    ConfigKey {
        key: "comment_discipline",
        config_type: ConfigType::Enum(&["encouraged", "required", "relaxed"]),
        description: "How strictly typed comments are enforced on issues",
    },
    ConfigKey {
        key: "kickoff_verification",
        config_type: ConfigType::Enum(&["local", "ci", "none"]),
        description: "Verification mode for agent kickoff tasks",
    },
    ConfigKey {
        key: "signing_enforcement",
        config_type: ConfigType::Enum(&["disabled", "audit", "enforced"]),
        description: "SSH signature verification level for coordination branch",
    },
    ConfigKey {
        key: "reminder_drift_threshold",
        config_type: ConfigType::Enum(&["0", "3", "5", "10", "15"]),
        description: "Prompts without crosslink usage before re-injecting reminder (0 = always)",
    },
    ConfigKey {
        key: "auto_steal_stale_locks",
        config_type: ConfigType::Enum(&["false", "2", "3", "5", "10"]),
        description: "Auto-steal stale locks after N * stale_timeout minutes (false = disabled)",
    },
    ConfigKey {
        key: "tracker_remote",
        config_type: ConfigType::String,
        description: "Git remote name for hub/knowledge branches (default: origin)",
    },
    ConfigKey {
        key: "blocked_git_commands",
        config_type: ConfigType::StringArray,
        description: "Git mutation commands blocked in all tracking modes",
    },
    ConfigKey {
        key: "gated_git_commands",
        config_type: ConfigType::StringArray,
        description: "Git commands allowed only with explicit user approval",
    },
    ConfigKey {
        key: "allowed_bash_prefixes",
        config_type: ConfigType::StringArray,
        description: "Bash commands that bypass the issue-required check",
    },
];

fn find_registry_key(key: &str) -> Option<&'static ConfigKey> {
    REGISTRY.iter().find(|k| k.key == key)
}

fn type_label(ct: ConfigType) -> &'static str {
    match ct {
        ConfigType::Bool => "bool",
        ConfigType::Enum(_) => "enum",
        ConfigType::String => "string",
        ConfigType::StringArray => "string[]",
    }
}

// ---------------------------------------------------------------------------
// Read / write helpers
// ---------------------------------------------------------------------------

fn read_config(crosslink_dir: &Path) -> Result<serde_json::Value> {
    let path = crosslink_dir.join("hook-config.json");
    let content =
        fs::read_to_string(&path).context("Failed to read .crosslink/hook-config.json")?;
    serde_json::from_str(&content).context("Failed to parse hook-config.json")
}

fn write_config(crosslink_dir: &Path, config: &serde_json::Value) -> Result<()> {
    let path = crosslink_dir.join("hook-config.json");
    let pretty = serde_json::to_string_pretty(config).context("Failed to serialize config")?;
    fs::write(&path, format!("{pretty}\n")).context("Failed to write hook-config.json")
}

fn read_defaults() -> Result<serde_json::Value> {
    serde_json::from_str(init::HOOK_CONFIG_JSON).context("embedded hook-config.json is invalid")
}

fn format_value(v: &serde_json::Value) -> String {
    match v {
        serde_json::Value::String(s) => s.clone(),
        serde_json::Value::Bool(b) => b.to_string(),
        serde_json::Value::Array(arr) => {
            let items: Vec<String> = arr
                .iter()
                .filter_map(|v| v.as_str().map(|s| s.to_string()))
                .collect();
            items.join(", ")
        }
        other => other.to_string(),
    }
}

// ---------------------------------------------------------------------------
// Subcommand dispatch
// ---------------------------------------------------------------------------

pub fn run(command: ConfigCommands, crosslink_dir: &Path) -> Result<()> {
    match command {
        ConfigCommands::Show => show(crosslink_dir),
        ConfigCommands::Get { key } => get(crosslink_dir, &key),
        ConfigCommands::Set {
            key,
            value,
            add,
            remove,
        } => set(
            crosslink_dir,
            &key,
            value.as_deref(),
            add.as_deref(),
            remove.as_deref(),
        ),
        ConfigCommands::List => list(),
        ConfigCommands::Reset { key } => reset(crosslink_dir, key.as_deref()),
        ConfigCommands::Diff => diff(crosslink_dir),
    }
}

// ---------------------------------------------------------------------------
// show — print all config with default annotations
// ---------------------------------------------------------------------------

fn show(crosslink_dir: &Path) -> Result<()> {
    let config = read_config(crosslink_dir)?;
    let defaults = read_defaults()?;

    for entry in REGISTRY {
        let current = config.get(entry.key);
        let default = defaults.get(entry.key);
        let current_str = current
            .map(format_value)
            .unwrap_or_else(|| "(unset)".into());
        let is_default = current == default;
        let annotation = if is_default {
            "(default)"
        } else {
            "(modified)"
        };

        if matches!(entry.config_type, ConfigType::StringArray) {
            println!(
                "{} {} {}:",
                entry.key,
                annotation,
                type_label(entry.config_type)
            );
            if let Some(serde_json::Value::Array(arr)) = current {
                for item in arr {
                    if let Some(s) = item.as_str() {
                        println!("  - {s}");
                    }
                }
            }
        } else {
            println!("{} = {} {}", entry.key, current_str, annotation);
        }
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// get — print a single value
// ---------------------------------------------------------------------------

fn get(crosslink_dir: &Path, key: &str) -> Result<()> {
    if find_registry_key(key).is_none() {
        bail!("Unknown config key: \"{key}\". Run `crosslink config list` to see available keys.");
    }

    let config = read_config(crosslink_dir)?;
    match config.get(key) {
        Some(serde_json::Value::Array(arr)) => {
            for item in arr {
                if let Some(s) = item.as_str() {
                    println!("{s}");
                }
            }
        }
        Some(v) => println!("{}", format_value(v)),
        None => println!("(unset)"),
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// set — validate and write a config value
// ---------------------------------------------------------------------------

fn set(
    crosslink_dir: &Path,
    key: &str,
    value: Option<&str>,
    add: Option<&str>,
    remove: Option<&str>,
) -> Result<()> {
    let entry = find_registry_key(key).ok_or_else(|| {
        anyhow::anyhow!(
            "Unknown config key: \"{key}\". Run `crosslink config list` to see available keys."
        )
    })?;

    let mut config = read_config(crosslink_dir)?;

    match entry.config_type {
        ConfigType::Bool => {
            let val = value
                .ok_or_else(|| anyhow::anyhow!("Usage: crosslink config set {key} <true|false>"))?;
            match val {
                "true" => config[key] = serde_json::Value::Bool(true),
                "false" => config[key] = serde_json::Value::Bool(false),
                _ => {
                    bail!("Invalid value for {key}: expected \"true\" or \"false\", got \"{val}\"")
                }
            }
            write_config(crosslink_dir, &config)?;
            println!("{key} = {val}");
        }
        ConfigType::Enum(valid) => {
            let val = value.ok_or_else(|| {
                anyhow::anyhow!("Usage: crosslink config set {key} <{}>", valid.join("|"))
            })?;
            if !valid.contains(&val) {
                bail!(
                    "Invalid value for {key}: \"{val}\". Valid values: {}",
                    valid.join(", ")
                );
            }
            config[key] = serde_json::Value::String(val.to_string());
            write_config(crosslink_dir, &config)?;
            println!("{key} = {val}");
        }
        ConfigType::String => {
            let val = value
                .ok_or_else(|| anyhow::anyhow!("Usage: crosslink config set {key} <value>"))?;
            config[key] = serde_json::Value::String(val.to_string());
            write_config(crosslink_dir, &config)?;
            println!("{key} = {val}");
        }
        ConfigType::StringArray => {
            if let Some(item) = add {
                let arr = config[key]
                    .as_array_mut()
                    .ok_or_else(|| anyhow::anyhow!("{key} is not an array in config"))?;
                let already = arr.iter().any(|v| v.as_str() == Some(item));
                if already {
                    println!("\"{item}\" already in {key}");
                } else {
                    arr.push(serde_json::Value::String(item.to_string()));
                    write_config(crosslink_dir, &config)?;
                    println!("Added \"{item}\" to {key}");
                }
            } else if let Some(item) = remove {
                let arr = config[key]
                    .as_array_mut()
                    .ok_or_else(|| anyhow::anyhow!("{key} is not an array in config"))?;
                let before = arr.len();
                arr.retain(|v| v.as_str() != Some(item));
                if arr.len() == before {
                    println!("\"{item}\" not found in {key}");
                } else {
                    write_config(crosslink_dir, &config)?;
                    println!("Removed \"{item}\" from {key}");
                }
            } else if let Some(val) = value {
                let items: Vec<serde_json::Value> = val
                    .split(',')
                    .map(|s| serde_json::Value::String(s.trim().to_string()))
                    .collect();
                config[key] = serde_json::Value::Array(items);
                write_config(crosslink_dir, &config)?;
                println!("Set {key} to {val}");
            } else {
                bail!(
                    "Usage: crosslink config set {key} \"val1,val2,...\" or --add/--remove \"val\""
                );
            }
        }
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// list — print all keys with types and descriptions
// ---------------------------------------------------------------------------

fn list() -> Result<()> {
    let defaults = read_defaults()?;

    println!("{:<28} {:<10} DESCRIPTION", "KEY", "TYPE");
    let sep = "-".repeat(78);
    println!("{sep}");

    for entry in REGISTRY {
        let default_str = defaults
            .get(entry.key)
            .map(|v| match v {
                serde_json::Value::Array(a) => format!("[{} items]", a.len()),
                other => format_value(other),
            })
            .unwrap_or_else(|| "(none)".into());

        println!(
            "{:<28} {:<10} {} (default: {})",
            entry.key,
            type_label(entry.config_type),
            entry.description,
            default_str
        );
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// reset — restore defaults (all or single key)
// ---------------------------------------------------------------------------

fn reset(crosslink_dir: &Path, key: Option<&str>) -> Result<()> {
    let defaults = read_defaults()?;

    if let Some(key) = key {
        if find_registry_key(key).is_none() {
            bail!(
                "Unknown config key: \"{key}\". Run `crosslink config list` to see available keys."
            );
        }
        let default_val = defaults
            .get(key)
            .ok_or_else(|| anyhow::anyhow!("No default found for {key}"))?;
        let mut config = read_config(crosslink_dir)?;
        config[key] = default_val.clone();
        write_config(crosslink_dir, &config)?;
        println!("Reset {key} to default: {}", format_value(default_val));
    } else {
        write_config(crosslink_dir, &defaults)?;
        println!("Reset all config to defaults.");
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// diff — compare current vs defaults, key-by-key
// ---------------------------------------------------------------------------

fn diff(crosslink_dir: &Path) -> Result<()> {
    let config = read_config(crosslink_dir)?;
    let defaults = read_defaults()?;
    let mut any_diff = false;

    for entry in REGISTRY {
        let current = config.get(entry.key);
        let default = defaults.get(entry.key);

        if current != default {
            any_diff = true;
            let cur_str = current
                .map(format_value)
                .unwrap_or_else(|| "(unset)".into());
            let def_str = default
                .map(format_value)
                .unwrap_or_else(|| "(unset)".into());

            if matches!(entry.config_type, ConfigType::StringArray) {
                println!("{} (modified):", entry.key);
                let cur_arr: Vec<&str> = current
                    .and_then(|v| v.as_array())
                    .map(|a| a.iter().filter_map(|v| v.as_str()).collect())
                    .unwrap_or_default();
                let def_arr: Vec<&str> = default
                    .and_then(|v| v.as_array())
                    .map(|a| a.iter().filter_map(|v| v.as_str()).collect())
                    .unwrap_or_default();

                for item in &cur_arr {
                    if !def_arr.contains(item) {
                        println!("  + {item}");
                    }
                }
                for item in &def_arr {
                    if !cur_arr.contains(item) {
                        println!("  - {item}");
                    }
                }
            } else {
                println!("{}: {} (default: {})", entry.key, cur_str, def_str);
            }
        }
    }

    if !any_diff {
        println!("No differences from defaults.");
    }
    Ok(())
}

use anyhow::{bail, Context, Result};
use std::path::{Path, PathBuf};
use std::process::Command;

use crate::ContainerCommands;

pub fn run(command: ContainerCommands) -> Result<()> {
    match command {
        ContainerCommands::Build {
            force,
            tag,
            dockerfile,
        } => build(force, tag.as_deref(), dockerfile.as_deref()),
        ContainerCommands::Start {
            worktree,
            name,
            prompt,
            issue,
            memory,
        } => {
            let path = PathBuf::from(&worktree);
            start(
                &path,
                name.as_deref(),
                prompt.as_deref(),
                issue,
                memory.as_deref(),
            )
        }
        ContainerCommands::Ps => ps(),
        ContainerCommands::Logs { name, follow, tail } => logs(&name, follow, tail),
        ContainerCommands::Stop { name } => stop(&name),
        ContainerCommands::Rm { name } => rm(&name),
        ContainerCommands::Kill { name } => kill(&name),
        ContainerCommands::Shell { name } => shell(&name),
        ContainerCommands::Snapshot { name, tag } => snapshot(&name, tag.as_deref()),
    }
}

const IMAGE_NAME: &str = "crosslink-agent";
const IMAGE_TAG: &str = "latest";
const CONTAINER_PREFIX: &str = "crosslink-task-";
const LABEL_AGENT: &str = "crosslink-agent=true";

const DOCKERFILE: &str = include_str!("../../resources/container/Dockerfile");
const ENTRYPOINT: &str = include_str!("../../resources/container/entrypoint.sh");

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Check if Docker is available and the daemon is running.
pub fn docker_available() -> bool {
    Command::new("docker")
        .args(["info"])
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
}

/// Find the crosslink binary path for copying into the build context.
fn find_crosslink_binary() -> Result<PathBuf> {
    std::env::current_exe().context("Could not determine crosslink binary path")
}

/// Compute a SHA-256 hash of a file (first 16 hex chars for brevity).
fn file_hash(path: &Path) -> Result<String> {
    use std::io::Read;
    let mut file = std::fs::File::open(path)?;
    // Read first 64KB — enough to detect changes without hashing a 50MB debug binary
    let mut buf = vec![0u8; 65536];
    let n = file.read(&mut buf)?;
    buf.truncate(n);

    // Simple FNV-1a hash (no external dep needed)
    let mut hash: u64 = 0xcbf29ce484222325;
    for &byte in &buf {
        hash ^= byte as u64;
        hash = hash.wrapping_mul(0x100000001b3);
    }
    Ok(format!("{:016x}", hash))
}

/// Resolve the main repo root (handles worktrees).
fn resolve_repo_root() -> Result<PathBuf> {
    let output = Command::new("git")
        .args(["rev-parse", "--show-toplevel"])
        .output()
        .context("Failed to run git rev-parse")?;
    if !output.status.success() {
        bail!("Not in a git repository");
    }
    let path = String::from_utf8(output.stdout)?.trim().to_string();
    Ok(PathBuf::from(path))
}

/// Resolve the git common dir (shared .git for worktrees).
fn resolve_git_common_dir() -> Result<PathBuf> {
    let output = Command::new("git")
        .args(["rev-parse", "--git-common-dir"])
        .output()
        .context("Failed to run git rev-parse --git-common-dir")?;
    if !output.status.success() {
        bail!("Not in a git repository");
    }
    let path_str = String::from_utf8(output.stdout)?.trim().to_string();
    let path = PathBuf::from(&path_str);
    // git returns relative paths sometimes
    if path.is_absolute() {
        Ok(path)
    } else {
        let cwd = std::env::current_dir()?;
        Ok(cwd.join(path).canonicalize()?)
    }
}

/// Detect host memory in GB.
fn detect_host_memory_gb() -> Option<u64> {
    // Linux: /proc/meminfo
    if let Ok(content) = std::fs::read_to_string("/proc/meminfo") {
        for line in content.lines() {
            if line.starts_with("MemTotal:") {
                let parts: Vec<&str> = line.split_whitespace().collect();
                if parts.len() >= 2 {
                    if let Ok(kb) = parts[1].parse::<u64>() {
                        return Some(kb / 1024 / 1024);
                    }
                }
            }
        }
    }
    // macOS: sysctl
    let output = Command::new("sysctl")
        .args(["-n", "hw.memsize"])
        .output()
        .ok()?;
    if output.status.success() {
        let bytes_str = String::from_utf8(output.stdout).ok()?.trim().to_string();
        let bytes: u64 = bytes_str.parse().ok()?;
        return Some(bytes / 1024 / 1024 / 1024);
    }
    None
}

/// Compute container memory limit: host RAM minus 2GB reserve, minimum 4GB.
fn compute_memory_limit(config_override: Option<&str>) -> String {
    if let Some(val) = config_override {
        if val != "auto" {
            return val.to_string();
        }
    }
    match detect_host_memory_gb() {
        Some(host_gb) => {
            let container_gb = if host_gb > 6 {
                host_gb - 2
            } else {
                4.max(host_gb)
            };
            format!("{}g", container_gb)
        }
        None => "8g".to_string(), // safe default
    }
}

/// Get the image hash label if present.
fn get_image_hash() -> Option<String> {
    let output = Command::new("docker")
        .args([
            "inspect",
            "--format",
            "{{index .Config.Labels \"crosslink-binary-hash\"}}",
            &format!("{}:{}", IMAGE_NAME, IMAGE_TAG),
        ])
        .output()
        .ok()?;
    if output.status.success() {
        let hash = String::from_utf8(output.stdout).ok()?.trim().to_string();
        if !hash.is_empty() && hash != "<no value>" {
            return Some(hash);
        }
    }
    None
}

/// Check if the image is stale compared to the running binary.
fn check_staleness() {
    let binary_hash = match find_crosslink_binary().and_then(|p| file_hash(&p)) {
        Ok(h) => h,
        Err(_) => return,
    };
    if let Some(image_hash) = get_image_hash() {
        if image_hash != binary_hash {
            eprintln!(
                "Warning: container image is stale (built from a different crosslink binary)."
            );
            eprintln!("Run 'crosslink container build' to update.");
        }
    }
}

/// RAII guard to clean up a temp build directory on drop.
struct BuildDirCleanup(PathBuf);
impl Drop for BuildDirCleanup {
    fn drop(&mut self) {
        let _ = std::fs::remove_dir_all(&self.0);
    }
}

// ---------------------------------------------------------------------------
// Commands
// ---------------------------------------------------------------------------

/// Build the crosslink agent container image.
pub fn build(force: bool, tag: Option<&str>, dockerfile: Option<&str>) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available. Install Docker and ensure the daemon is running.");
    }

    let tag = tag.unwrap_or(IMAGE_TAG);
    let image = format!("{}:{}", IMAGE_NAME, tag);

    // Create temp build context
    let build_path =
        std::env::temp_dir().join(format!("crosslink-container-build-{}", std::process::id()));
    std::fs::create_dir_all(&build_path).context("Failed to create temp build directory")?;
    // Clean up on exit (best-effort)
    let _cleanup = BuildDirCleanup(build_path.clone());

    // Write Dockerfile
    let dockerfile_content = if let Some(path) = dockerfile {
        std::fs::read_to_string(path)
            .with_context(|| format!("Failed to read custom Dockerfile: {}", path))?
    } else {
        DOCKERFILE.to_string()
    };
    std::fs::write(build_path.join("Dockerfile"), &dockerfile_content)?;

    // Write entrypoint
    std::fs::write(build_path.join("entrypoint.sh"), ENTRYPOINT)?;

    // Copy crosslink binary
    let binary = find_crosslink_binary()?;
    std::fs::copy(&binary, build_path.join("crosslink"))
        .context("Failed to copy crosslink binary to build context")?;

    // Compute binary hash for staleness detection
    let binary_hash = file_hash(&binary).unwrap_or_else(|_| "unknown".to_string());

    println!("Building container image: {}", image);

    let mut cmd = Command::new("docker");
    cmd.args(["build", "-t", &image]);
    cmd.args(["--label", LABEL_AGENT]);
    cmd.args(["--label", &format!("crosslink-binary-hash={}", binary_hash)]);
    if force {
        cmd.arg("--no-cache");
    }
    cmd.arg(".");
    cmd.current_dir(build_path);

    let status = cmd.status().context("Failed to run docker build")?;
    if !status.success() {
        bail!("Docker build failed");
    }

    println!("Image built successfully: {}", image);
    println!("Binary hash: {}", binary_hash);
    Ok(())
}

/// Start a task container for a worktree.
pub fn start(
    worktree_path: &Path,
    name: Option<&str>,
    prompt_file: Option<&str>,
    issue_id: Option<i64>,
    memory: Option<&str>,
) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available. Install Docker and ensure the daemon is running.");
    }

    check_staleness();

    let worktree_abs = std::fs::canonicalize(worktree_path)
        .with_context(|| format!("Worktree not found: {}", worktree_path.display()))?;

    // Derive container name from worktree directory name
    let worktree_slug = worktree_abs
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("unknown");
    let container_name = name
        .map(|n| n.to_string())
        .unwrap_or_else(|| format!("{}{}", CONTAINER_PREFIX, worktree_slug));

    // Resolve paths
    let git_common_dir = resolve_git_common_dir()?;
    let repo_root = resolve_repo_root()?;
    let hub_cache = repo_root.join(".crosslink").join(".hub-cache");

    // Read the prompt file
    let prompt_path = prompt_file
        .map(PathBuf::from)
        .unwrap_or_else(|| worktree_abs.join("KICKOFF.md"));
    if !prompt_path.exists() {
        bail!(
            "Prompt file not found: {}. Write a KICKOFF.md in the worktree first.",
            prompt_path.display()
        );
    }
    let prompt = std::fs::read_to_string(&prompt_path).context("Failed to read prompt file")?;

    // Resolve credentials
    let home = std::env::var("HOME").unwrap_or_else(|_| "/home/user".to_string());
    let credentials_path = PathBuf::from(&home)
        .join(".claude")
        .join(".credentials.json");
    if !credentials_path.exists() {
        bail!(
            "Claude credentials not found at {}. Run 'claude' to authenticate first.",
            credentials_path.display()
        );
    }

    // Compute resource limits
    let memory_limit = compute_memory_limit(memory);

    // Derive agent ID
    let agent_id = format!("container--{}", worktree_slug);

    let image = format!("{}:{}", IMAGE_NAME, IMAGE_TAG);

    println!("Starting task container: {}", container_name);
    println!("  Worktree: {}", worktree_abs.display());
    println!("  Memory:   {}", memory_limit);
    println!("  Agent:    {}", agent_id);

    let mut cmd = Command::new("docker");
    cmd.args(["run", "-d"]);
    cmd.args(["--name", &container_name]);
    cmd.args(["--label", LABEL_AGENT]);
    cmd.args(["--label", &format!("crosslink-task={}", worktree_slug)]);
    if let Some(id) = issue_id {
        cmd.args(["--label", &format!("crosslink-issue={}", id)]);
    }
    cmd.args(["--memory", &memory_limit]);

    // Mount worktree read-write
    cmd.args([
        "-v",
        &format!("{}:/workspaces/{}", worktree_abs.display(), worktree_slug),
    ]);

    // Mount .git common dir (shared git objects)
    cmd.args(["-v", &format!("{}:/repo/.git:rw", git_common_dir.display())]);

    // --- Worktree git fixup ---
    // A git worktree's `.git` file and the corresponding `gitdir` back-pointer
    // contain absolute host paths. Inside the container these paths don't exist.
    // We create temp files with container-side paths and bind-mount them *over*
    // the originals so the host files stay untouched.
    let dot_git_path = worktree_abs.join(".git");
    if dot_git_path.is_file() {
        // Store fixup files in the worktree's .crosslink/ dir so they persist
        // for the lifetime of the container (bind mounts need the source files alive).
        let fixup_dir = worktree_abs.join(".crosslink").join("container-git-fixup");
        std::fs::create_dir_all(&fixup_dir).context("Failed to create git fixup dir")?;

        let container_workspace = format!("/workspaces/{}", worktree_slug);
        let container_gitdir = format!("/repo/.git/worktrees/{}", worktree_slug);

        // Override the worktree's .git file → point to container-side gitdir
        let override_dot_git = fixup_dir.join("dot-git");
        std::fs::write(&override_dot_git, format!("gitdir: {}\n", container_gitdir))?;

        // Override the gitdir back-pointer → point to container-side worktree
        let override_gitdir = fixup_dir.join("gitdir");
        std::fs::write(&override_gitdir, format!("{}/.git\n", container_workspace))?;

        // Mount overrides (shadows originals inside container only)
        cmd.args([
            "-v",
            &format!(
                "{}:{}/.git:ro",
                override_dot_git.display(),
                container_workspace
            ),
        ]);
        cmd.args([
            "-v",
            &format!(
                "{}:{}/gitdir:ro",
                override_gitdir.display(),
                container_gitdir
            ),
        ]);
    }

    // Mount hub cache if it exists
    if hub_cache.exists() {
        cmd.args([
            "-v",
            &format!("{}:/repo/.crosslink/.hub-cache:rw", hub_cache.display()),
        ]);
    }

    // Mount credentials read-only
    cmd.args([
        "-v",
        &format!(
            "{}:/host-auth/.credentials.json:ro",
            credentials_path.display()
        ),
    ]);

    // Environment
    cmd.args(["-e", &format!("AGENT_ID={}", agent_id)]);
    cmd.args(["-e", "CLAUDE_CONFIG_DIR=/home/agent/.claude"]);

    // Pass host UID/GID so the entrypoint can remap the agent user to match,
    // avoiding permission issues with bind-mounted files.
    if let Ok(uid_output) = Command::new("id").arg("-u").output() {
        if uid_output.status.success() {
            let uid = String::from_utf8_lossy(&uid_output.stdout)
                .trim()
                .to_string();
            cmd.args(["-e", &format!("HOST_UID={}", uid)]);
        }
    }
    if let Ok(gid_output) = Command::new("id").arg("-g").output() {
        if gid_output.status.success() {
            let gid = String::from_utf8_lossy(&gid_output.stdout)
                .trim()
                .to_string();
            cmd.args(["-e", &format!("HOST_GID={}", gid)]);
        }
    }

    // Image and command
    cmd.arg(&image);
    cmd.args([
        "claude",
        "--dangerously-skip-permissions",
        "--model",
        "opus",
        "--",
        &prompt,
    ]);

    let output = cmd.output().context("Failed to start container")?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!("Failed to start container: {}", stderr.trim());
    }

    let container_id = String::from_utf8_lossy(&output.stdout).trim().to_string();
    println!(
        "  Container ID: {}...",
        &container_id[..12.min(container_id.len())]
    );

    // Write container ID to worktree for tracking
    let id_file = worktree_abs.join(".crosslink").join("container-id");
    if let Some(parent) = id_file.parent() {
        std::fs::create_dir_all(parent).ok();
    }
    std::fs::write(&id_file, &container_id).ok();

    println!();
    println!("Task container started.");
    println!("  Check status: crosslink container ps");
    println!(
        "  View logs:    crosslink container logs {}",
        container_name
    );
    println!(
        "  Shell in:     crosslink container shell {}",
        container_name
    );
    println!(
        "  Stop:         crosslink container stop {}",
        container_name
    );

    Ok(())
}

/// List running crosslink task containers.
pub fn ps() -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    let output = Command::new("docker")
        .args([
            "ps",
            "-a",
            "--filter",
            &format!("label={}", LABEL_AGENT),
            "--format",
            "table {{.Names}}\t{{.Status}}\t{{.Label \"crosslink-task\"}}\t{{.Label \"crosslink-issue\"}}",
        ])
        .output()
        .context("Failed to list containers")?;

    if !output.status.success() {
        bail!("Failed to list containers");
    }

    let stdout = String::from_utf8_lossy(&output.stdout);
    if stdout.trim().is_empty() || stdout.lines().count() <= 1 {
        println!("No crosslink task containers found.");
    } else {
        print!("{}", stdout);
    }
    Ok(())
}

/// Stream logs from a container.
pub fn logs(name: &str, follow: bool, tail: Option<u32>) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    let mut cmd = Command::new("docker");
    cmd.args(["logs"]);
    if follow {
        cmd.arg("--follow");
    }
    let tail_str = tail.unwrap_or(100).to_string();
    cmd.args(["--tail", &tail_str]);
    cmd.arg(name);

    let status = cmd.status().context("Failed to read container logs")?;
    if !status.success() {
        bail!(
            "Failed to read logs for container '{}'. Does it exist?",
            name
        );
    }
    Ok(())
}

/// Stop a running container.
pub fn stop(name: &str) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    println!("Stopping container: {}", name);
    let status = Command::new("docker")
        .args(["stop", name])
        .status()
        .context("Failed to stop container")?;

    if !status.success() {
        bail!("Failed to stop container '{}'", name);
    }
    println!("Container stopped.");
    Ok(())
}

/// Remove a stopped container.
pub fn rm(name: &str) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    println!("Removing container: {}", name);
    let status = Command::new("docker")
        .args(["rm", name])
        .status()
        .context("Failed to remove container")?;

    if !status.success() {
        bail!("Failed to remove container '{}'", name);
    }
    println!("Container removed.");
    Ok(())
}

/// Stop and remove a container.
pub fn kill(name: &str) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    println!("Stopping and removing container: {}", name);
    // Stop first (ignore errors — may already be stopped)
    let _ = Command::new("docker").args(["stop", name]).status();
    let status = Command::new("docker")
        .args(["rm", "-f", name])
        .status()
        .context("Failed to remove container")?;

    if !status.success() {
        bail!("Failed to remove container '{}'", name);
    }
    println!("Container removed.");
    Ok(())
}

/// Drop into a shell inside a running container.
pub fn shell(name: &str) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    let status = Command::new("docker")
        .args(["exec", "-it", name, "/bin/bash"])
        .status()
        .context("Failed to exec into container")?;

    if !status.success() {
        bail!("Shell exited with error");
    }
    Ok(())
}

/// Snapshot a running container as a cached image.
pub fn snapshot(name: &str, tag: Option<&str>) -> Result<()> {
    if !docker_available() {
        bail!("Docker is not available.");
    }

    let tag = tag.unwrap_or("cached");
    let image = format!("{}:{}", IMAGE_NAME, tag);

    println!("Snapshotting container '{}' as '{}'...", name, image);
    let status = Command::new("docker")
        .args(["commit", name, &image])
        .status()
        .context("Failed to snapshot container")?;

    if !status.success() {
        bail!("Failed to snapshot container '{}'", name);
    }
    println!("Snapshot saved: {}", image);
    println!("Use with: crosslink container start --image {}", image);
    Ok(())
}

