pub fn run(command: ContextCommands, crosslink_dir: &Path) -> Result<()> {
    match command {
        ContextCommands::Measure { verbose } => measure(crosslink_dir, verbose),
        ContextCommands::Check => {
            let claude_dir = crosslink_dir
                .parent()
                .context("Cannot determine project root")?
                .join(".claude");
            check(crosslink_dir, &claude_dir)
        }
    }
}

// ---------------------------------------------------------------------------
// measure — report context injection sizes
// ---------------------------------------------------------------------------

fn measure(crosslink_dir: &Path, verbose: bool) -> Result<()> {
    let project_root = crosslink_dir
        .parent()
        .context("Cannot determine project root")?;

    println!("Context injection measurement");
    println!("{}", "=".repeat(60));

    // 1. Rule files
    let rules_dir = crosslink_dir.join("rules");
    let mut total_rules: usize = 0;
    let mut active_rules: usize = 0;
    let mut dormant_rules: usize = 0;

    // Detect active languages
    let active_langs = detect_active_languages(project_root);

    let rules_local_dir = crosslink_dir.join("rules.local");

    println!("\n## Rule files (.crosslink/rules/)");
    println!("{:<35} {:>8} {:>8}  STATUS", "FILE", "BYTES", "~TOKENS");
    println!("{}", "-".repeat(65));

    // Collect overridden filenames from rules.local/
    let local_overrides: std::collections::HashSet<String> = if rules_local_dir.is_dir() {
        fs::read_dir(&rules_local_dir)
            .ok()
            .into_iter()
            .flatten()
            .filter_map(|e| e.ok())
            .map(|e| e.file_name().to_string_lossy().to_string())
            .collect()
    } else {
        std::collections::HashSet::new()
    };

    if rules_dir.is_dir() {
        let mut entries: Vec<_> = fs::read_dir(&rules_dir)
            .context("Failed to read rules directory")?
            .filter_map(|e| e.ok())
            .filter(|e| {
                e.path()
                    .extension()
                    .map(|ext| ext == "md" || ext == "txt")
                    .unwrap_or(false)
            })
            .collect();
        entries.sort_by_key(|e| e.file_name());

        for entry in &entries {
            let path = entry.path();
            let filename = entry.file_name().to_string_lossy().to_string();

            // If overridden by rules.local/, show the local version's size
            let (size, suffix) = if local_overrides.contains(&filename) {
                let local_path = rules_local_dir.join(&filename);
                let s = fs::metadata(&local_path)
                    .map(|m| m.len() as usize)
                    .unwrap_or(0);
                (s, " (local)")
            } else {
                let s = fs::metadata(&path).map(|m| m.len() as usize).unwrap_or(0);
                (s, "")
            };
            let tokens = size / 4;
            total_rules += size;

            let is_active = is_rule_active(&filename, &active_langs);
            let status = if is_active {
                active_rules += size;
                "active"
            } else {
                dormant_rules += size;
                "dormant"
            };

            println!(
                "{:<35} {:>8} {:>8}  {}{}",
                filename, size, tokens, status, suffix
            );
        }
    }

    // Show additive rules from rules.local/ (files not present in rules/)
    if rules_local_dir.is_dir() {
        let base_files: std::collections::HashSet<String> = if rules_dir.is_dir() {
            fs::read_dir(&rules_dir)
                .ok()
                .into_iter()
                .flatten()
                .filter_map(|e| e.ok())
                .map(|e| e.file_name().to_string_lossy().to_string())
                .collect()
        } else {
            std::collections::HashSet::new()
        };

        let mut local_entries: Vec<_> = fs::read_dir(&rules_local_dir)
            .ok()
            .into_iter()
            .flatten()
            .filter_map(|e| e.ok())
            .filter(|e| {
                let name = e.file_name().to_string_lossy().to_string();
                !base_files.contains(&name)
                    && e.path()
                        .extension()
                        .map(|ext| ext == "md" || ext == "txt")
                        .unwrap_or(false)
            })
            .collect();
        local_entries.sort_by_key(|e| e.file_name());

        for entry in &local_entries {
            let path = entry.path();
            let filename = entry.file_name().to_string_lossy().to_string();
            let size = fs::metadata(&path).map(|m| m.len() as usize).unwrap_or(0);
            let tokens = size / 4;
            total_rules += size;
            active_rules += size;

            println!("{:<35} {:>8} {:>8}  active (local)", filename, size, tokens);
        }
    }

    println!();
    println!(
        "  Total rules:   {:>8} bytes ({} tokens)",
        total_rules,
        total_rules / 4
    );
    println!(
        "  Active rules:  {:>8} bytes ({} tokens)",
        active_rules,
        active_rules / 4
    );
    println!(
        "  Dormant rules: {:>8} bytes ({} tokens)",
        dormant_rules,
        dormant_rules / 4
    );

    // 2. Active languages
    println!("\n## Detected languages");
    if active_langs.is_empty() {
        println!("  (none detected)");
    } else {
        for lang in &active_langs {
            println!("  - {}", lang);
        }
    }

    // 3. CLAUDE.md
    let claude_md = project_root.join("CLAUDE.md");
    let claude_md_size = if claude_md.is_file() {
        fs::metadata(&claude_md)
            .map(|m| m.len() as usize)
            .unwrap_or(0)
    } else {
        0
    };

    println!("\n## CLAUDE.md");
    if claude_md_size > 0 {
        println!(
            "  {:>8} bytes ({} tokens)",
            claude_md_size,
            claude_md_size / 4
        );
    } else {
        println!("  (not found)");
    }

    // 4. Skill files (.claude/commands/)
    let commands_dir = project_root.join(".claude/commands");
    let mut total_skills: usize = 0;

    println!("\n## Skill files (.claude/commands/)");
    if commands_dir.is_dir() {
        println!("{:<35} {:>8} {:>8}", "FILE", "BYTES", "~TOKENS");
        println!("{}", "-".repeat(55));

        let mut entries: Vec<_> = fs::read_dir(&commands_dir)
            .context("Failed to read commands directory")?
            .filter_map(|e| e.ok())
            .filter(|e| e.path().extension().map(|ext| ext == "md").unwrap_or(false))
            .collect();
        entries.sort_by_key(|e| e.file_name());

        for entry in &entries {
            let path = entry.path();
            let filename = entry.file_name().to_string_lossy().to_string();
            let size = fs::metadata(&path).map(|m| m.len() as usize).unwrap_or(0);
            total_skills += size;
            println!("{:<35} {:>8} {:>8}", filename, size, size / 4);
        }
        println!();
        println!(
            "  Total skills: {:>8} bytes ({} tokens)",
            total_skills,
            total_skills / 4
        );
    } else {
        println!("  (not found)");
    }

    // 5. Estimated behavioral guard size (first prompt)
    let tree_est: usize = 2000;
    let deps_est: usize = 1200;
    let wrapper_est: usize = 500;
    let full_guard = tree_est + deps_est + active_rules + wrapper_est;

    println!("\n## Estimated first-prompt injection");
    println!("  Project tree:    ~{:>6} bytes", tree_est);
    println!("  Dependencies:    ~{:>6} bytes", deps_est);
    println!("  Active rules:     {:>6} bytes", active_rules);
    println!("  Wrapper/headers: ~{:>6} bytes", wrapper_est);
    println!("  ─────────────────────────");
    println!(
        "  Total:           ~{:>6} bytes (~{} tokens)",
        full_guard,
        full_guard / 4
    );

    // 6. Condensed reminder estimate
    let condensed_est: usize = 500;
    println!("\n## Condensed reminder (subsequent prompts)");
    println!(
        "  Estimated:       ~{:>6} bytes (~{} tokens)",
        condensed_est,
        condensed_est / 4
    );

    // 7. Savings comparison
    println!("\n## Adaptive reminder savings (over 50 prompts)");
    let always_total = full_guard + condensed_est * 49;
    // With adaptive (threshold=5): full guard + ~9 condensed reminders
    let adaptive_reminders = 49 / 5; // roughly 9 reminders
    let adaptive_total = full_guard + condensed_est * adaptive_reminders;
    let saved = always_total.saturating_sub(adaptive_total);
    println!(
        "  Always-inject:   ~{:>8} bytes ({} tokens)",
        always_total,
        always_total / 4
    );
    println!(
        "  Adaptive (t=5):  ~{:>8} bytes ({} tokens)",
        adaptive_total,
        adaptive_total / 4
    );
    println!(
        "  Saved:           ~{:>8} bytes ({} tokens, {:.0}%)",
        saved,
        saved / 4,
        if always_total > 0 {
            saved as f64 / always_total as f64 * 100.0
        } else {
            0.0
        }
    );

    if verbose {
        println!("\n## Hook config");
        let config_path = crosslink_dir.join("hook-config.json");
        if config_path.is_file() {
            let content =
                fs::read_to_string(&config_path).context("Failed to read hook-config.json")?;
            println!("{}", content);
        } else {
            println!("  (not found)");
        }
    }

    Ok(())
}

fn detect_active_languages(project_root: &Path) -> Vec<String> {
    let mut found = Vec::new();
    let mut seen = std::collections::HashSet::new();

    // Check project root and immediate subdirs
    let mut check_dirs = vec![project_root.to_path_buf()];
    if let Ok(entries) = fs::read_dir(project_root) {
        for entry in entries.filter_map(|e| e.ok()) {
            let path = entry.path();
            if path.is_dir() {
                let name = entry.file_name().to_string_lossy().to_string();
                if !name.starts_with('.') {
                    check_dirs.push(path);
                }
            }
        }
    }

    for dir in &check_dirs {
        for &(manifest, lang, _rule_file) in LANGUAGE_MANIFESTS {
            if dir.join(manifest).exists() && seen.insert(lang.to_string()) {
                found.push(lang.to_string());
            }
        }
    }

    found
}

fn is_rule_active(filename: &str, active_langs: &[String]) -> bool {
    // Always-active files
    if matches!(
        filename,
        "global.md"
            | "project.md"
            | "tracking-strict.md"
            | "tracking-normal.md"
            | "tracking-relaxed.md"
            | "sanitize-patterns.txt"
            | "knowledge.md"
            | "web.md"
    ) {
        return true;
    }

    // Check if the rule matches a detected language
    for &(_manifest, lang, rule_file) in LANGUAGE_MANIFESTS {
        if filename == rule_file && active_langs.iter().any(|l| l == lang) {
            return true;
        }
    }

    false
}

// ---------------------------------------------------------------------------
// check — verify crosslink deployment integrity
// ---------------------------------------------------------------------------

fn check(crosslink_dir: &Path, claude_dir: &Path) -> Result<()> {
    let mut problems = 0;

    println!("Crosslink deployment check");
    println!("{}", "=".repeat(40));

    // 1. Rule files
    println!("\n## Rule files");
    let rules_dir = crosslink_dir.join("rules");
    for &name in EXPECTED_RULES {
        let path = rules_dir.join(name);
        if path.is_file() {
            println!("  OK  {}", name);
        } else {
            println!("  MISSING  {}", name);
            problems += 1;
        }
    }

    // Also check language rule files
    for &(_name, _content) in init::RULE_FILES {
        let path = rules_dir.join(_name);
        if path.is_file() {
            // verbose: could print OK
        } else {
            println!("  MISSING  {}", _name);
            problems += 1;
        }
    }

    // 2. Hook files
    println!("\n## Hook files");
    let hooks_dir = claude_dir.join("hooks");
    for &name in EXPECTED_HOOKS {
        let path = hooks_dir.join(name);
        if path.is_file() {
            println!("  OK  {}", name);
        } else {
            println!("  MISSING  {}", name);
            problems += 1;
        }
    }

    // 3. Command files
    println!("\n## Command files");
    let commands_dir = claude_dir.join("commands");
    for &name in EXPECTED_COMMANDS {
        let path = commands_dir.join(name);
        if path.is_file() {
            println!("  OK  {}", name);
        } else {
            println!("  MISSING  {}", name);
            problems += 1;
        }
    }

    // 4. Hook config
    println!("\n## Configuration");
    let config_path = crosslink_dir.join("hook-config.json");
    if config_path.is_file() {
        match fs::read_to_string(&config_path) {
            Ok(content) => match serde_json::from_str::<serde_json::Value>(&content) {
                Ok(_) => println!("  OK  hook-config.json (valid JSON)"),
                Err(e) => {
                    println!("  INVALID  hook-config.json: {}", e);
                    problems += 1;
                }
            },
            Err(e) => {
                println!("  ERROR  hook-config.json: {}", e);
                problems += 1;
            }
        }
    } else {
        println!("  MISSING  hook-config.json");
        problems += 1;
    }

    // Summary
    println!();
    if problems == 0 {
        println!("All checks passed.");
    } else {
        println!(
            "{} problem(s) found. Run `crosslink init --force` to repair.",
            problems
        );
        std::process::exit(1);
    }

    Ok(())
}

//! Code clone detection via cpitd (Copy Paste Is The Devil).
//!
//! Shells out to the `cpitd` Python tool, parses its JSON output,
//! and creates crosslink issues for detected code clones.

use std::collections::HashMap;
use std::process::Command;

use anyhow::{bail, Context, Result};
use serde::Deserialize;

use crate::CpitdCommands;

use crate::db::Database;

pub fn run(command: CpitdCommands, db: &Database, quiet: bool) -> Result<()> {
    match command {
        CpitdCommands::Scan {
            paths,
            min_tokens,
            ignore,
            dry_run,
        } => scan(db, &paths, min_tokens, &ignore, dry_run, quiet),
        CpitdCommands::Status => status(db),
        CpitdCommands::Clear => clear(db),
    }
}
use crate::utils::format_issue_id;

// ---------------------------------------------------------------------------
// cpitd JSON output types
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
struct CpitdOutput {
    clone_reports: Vec<CpitdCloneReport>,
    total_pairs: usize,
}

#[derive(Debug, Deserialize)]
struct CpitdCloneReport {
    file_a: String,
    file_b: String,
    total_cloned_lines: usize,
    groups: Vec<CpitdCloneGroup>,
}

#[derive(Debug, Deserialize)]
struct CpitdCloneGroup {
    lines_a: Vec<usize>,
    lines_b: Vec<usize>,
    line_count: usize,
    token_count: usize,
}

// ---------------------------------------------------------------------------
// Installation detection
// ---------------------------------------------------------------------------

fn find_cpitd() -> bool {
    Command::new("cpitd")
        .arg("--version")
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false)
}

fn suggest_install() -> Result<()> {
    bail!(
        "cpitd is not installed or not found in PATH.\n\n\
         cpitd (Copy Paste Is The Devil) is a language-agnostic code clone\n\
         detector that integrates with crosslink to track duplicated code\n\
         as issues.\n\n\
         Run `crosslink init --force` to auto-install, or install manually:\n\n\
         \x20 pip install cpitd\n\n\
         Or visit: https://github.com/scythia-marrow/cpitd"
    )
}

// ---------------------------------------------------------------------------
// Running cpitd
// ---------------------------------------------------------------------------

fn run_cpitd(paths: &[String], min_tokens: u32, ignore_patterns: &[String]) -> Result<CpitdOutput> {
    let mut cmd = Command::new("cpitd");

    if paths.is_empty() {
        cmd.arg(".");
    } else {
        for p in paths {
            cmd.arg(p);
        }
    }

    cmd.arg("--format").arg("json");
    cmd.arg("--min-tokens").arg(min_tokens.to_string());

    for pattern in ignore_patterns {
        cmd.arg("--ignore").arg(pattern);
    }

    let output = cmd.output().context("Failed to execute cpitd")?;

    let stdout = String::from_utf8(output.stdout).context("cpitd output is not valid UTF-8")?;

    if stdout.trim().is_empty() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        if stderr.trim().is_empty() {
            // cpitd exited 0 with no output means no clones in some edge cases
            return Ok(CpitdOutput {
                clone_reports: vec![],
                total_pairs: 0,
            });
        }
        bail!("cpitd produced no output. stderr: {}", stderr.trim());
    }

    serde_json::from_str(&stdout).context("Failed to parse cpitd JSON output")
}

// ---------------------------------------------------------------------------
// Deduplication
// ---------------------------------------------------------------------------

fn dedup_marker(file_a: &str, file_b: &str) -> String {
    let (a, b) = if file_a <= file_b {
        (file_a, file_b)
    } else {
        (file_b, file_a)
    };
    format!("<!-- cpitd:file_a={}:file_b={} -->", a, b)
}

fn find_existing_clone_issue(db: &Database, file_a: &str, file_b: &str) -> Result<Option<i64>> {
    let marker = dedup_marker(file_a, file_b);
    let issues = db.list_issues(Some("open"), Some("cpitd"), None)?;
    for issue in issues {
        if let Some(ref desc) = issue.description {
            if desc.contains(&marker) {
                return Ok(Some(issue.id));
            }
        }
    }
    Ok(None)
}

// ---------------------------------------------------------------------------
// Issue creation
// ---------------------------------------------------------------------------

fn shorten_path(path: &str) -> &str {
    std::path::Path::new(path)
        .file_name()
        .and_then(|f| f.to_str())
        .unwrap_or(path)
}

fn format_clone_description(report: &CpitdCloneReport) -> String {
    let marker = dedup_marker(&report.file_a, &report.file_b);

    let mut desc = format!(
        "{}\n\n\
         Detected code clones between:\n\
         - `{}`\n\
         - `{}`\n\n\
         Total cloned lines: {}\n\n\
         Clone groups:\n",
        marker, report.file_a, report.file_b, report.total_cloned_lines,
    );

    for (i, group) in report.groups.iter().enumerate() {
        desc.push_str(&format!(
            "{}. Lines {}-{} <-> Lines {}-{} ({} lines, {} tokens)\n",
            i + 1,
            group.lines_a[0],
            group.lines_a[1],
            group.lines_b[0],
            group.lines_b[1],
            group.line_count,
            group.token_count,
        ));
    }

    desc.push_str("\nConsider extracting shared logic into a common function or module.");
    desc
}

fn create_clone_issue(db: &Database, report: &CpitdCloneReport, quiet: bool) -> Result<i64> {
    let title = format!(
        "Code clone: {} <-> {} ({} lines)",
        shorten_path(&report.file_a),
        shorten_path(&report.file_b),
        report.total_cloned_lines,
    );

    let description = format_clone_description(report);
    let id = db.create_issue(&title, Some(&description), "low")?;
    db.add_label(id, "cpitd")?;
    db.add_label(id, "refactor")?;

    if !quiet {
        println!("  Created issue {}: {}", format_issue_id(id), title);
    }

    Ok(id)
}

fn relate_clone_issues(db: &Database, created: &[(i64, String, String)]) -> Result<()> {
    let mut file_to_issues: HashMap<&str, Vec<i64>> = HashMap::new();
    for (id, file_a, file_b) in created {
        file_to_issues.entry(file_a).or_default().push(*id);
        file_to_issues.entry(file_b).or_default().push(*id);
    }
    for ids in file_to_issues.values() {
        for i in 0..ids.len() {
            for j in (i + 1)..ids.len() {
                // Ignore errors (e.g. relation already exists)
                let _ = db.add_relation(ids[i], ids[j]);
            }
        }
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Public commands
// ---------------------------------------------------------------------------

pub fn scan(
    db: &Database,
    paths: &[String],
    min_tokens: u32,
    ignore_patterns: &[String],
    dry_run: bool,
    quiet: bool,
) -> Result<()> {
    if !find_cpitd() {
        return suggest_install();
    }

    if !quiet {
        println!("Running cpitd clone detection...");
    }

    let output = run_cpitd(paths, min_tokens, ignore_patterns)?;

    if output.clone_reports.is_empty() {
        if !quiet {
            println!("No code clones detected.");
        }
        return Ok(());
    }

    if !quiet {
        println!("Found {} clone pair(s).\n", output.total_pairs);
    }

    if dry_run {
        for report in &output.clone_reports {
            println!(
                "  Would create: {} <-> {} ({} lines, {} group(s))",
                report.file_a,
                report.file_b,
                report.total_cloned_lines,
                report.groups.len(),
            );
        }
        return Ok(());
    }

    let mut created_count = 0usize;
    let mut updated_count = 0usize;
    let mut created_ids: Vec<(i64, String, String)> = Vec::new();

    for report in &output.clone_reports {
        match find_existing_clone_issue(db, &report.file_a, &report.file_b)? {
            Some(existing_id) => {
                let comment = format!(
                    "[cpitd rescan] {} total cloned lines, {} group(s)",
                    report.total_cloned_lines,
                    report.groups.len(),
                );
                db.add_comment(existing_id, &comment, "note")?;
                updated_count += 1;
                if !quiet {
                    println!(
                        "  Updated issue {} (clone still present)",
                        format_issue_id(existing_id)
                    );
                }
            }
            None => {
                let id = create_clone_issue(db, report, quiet)?;
                created_ids.push((id, report.file_a.clone(), report.file_b.clone()));
                created_count += 1;
            }
        }
    }

    if created_ids.len() > 1 {
        relate_clone_issues(db, &created_ids)?;
    }

    if !quiet {
        println!(
            "\ncpitd scan complete: {} created, {} updated",
            created_count, updated_count,
        );
    }

    Ok(())
}

pub fn status(db: &Database) -> Result<()> {
    let issues = db.list_issues(Some("open"), Some("cpitd"), None)?;

    if issues.is_empty() {
        println!("No open cpitd clone issues.");
    } else {
        println!("{} open clone issue(s):\n", issues.len());
        for issue in &issues {
            println!("  {:<5} {}", format_issue_id(issue.id), issue.title);
        }
    }

    Ok(())
}

pub fn clear(db: &Database) -> Result<()> {
    let issues = db.list_issues(Some("open"), Some("cpitd"), None)?;

    if issues.is_empty() {
        println!("No open cpitd clone issues to close.");
        return Ok(());
    }

    let count = issues.len();
    for issue in &issues {
        db.close_issue(issue.id)?;
    }

    println!("Closed {} cpitd clone issue(s).", count);
    Ok(())
}

