/// Progress tuple: (completed subissues, total subissues)
type Progress = Option<(i32, i32)>;

/// Scored issue with priority score and progress
type ScoredIssue = (Issue, i32, Progress);

/// Best-effort load of lock state for filtering. Returns (LocksFile, my_agent_id) or None.
fn load_locks_filter(crosslink_dir: &Path) -> Option<(LocksFile, String)> {
    let agent = crate::identity::AgentConfig::load(crosslink_dir).ok()??;
    let sync = crate::sync::SyncManager::new(crosslink_dir).ok()?;
    let _ = sync.init_cache();
    let _ = sync.fetch();
    let locks = sync.read_locks_auto().ok()?;
    Some((locks, agent.agent_id))
}

/// Priority order for sorting (higher = more important)
fn priority_weight(priority: &str) -> i32 {
    match priority {
        "critical" => 4,
        "high" => 3,
        "medium" => 2,
        "low" => 1,
        _ => 0,
    }
}

/// Calculate progress for issues with subissues
fn calculate_progress(db: &Database, issue: &Issue) -> Result<Progress> {
    let subissues = db.get_subissues(issue.id)?;
    if subissues.is_empty() {
        return Ok(None);
    }

    let total = subissues.len() as i32;
    let closed = subissues.iter().filter(|s| s.status == "closed").count() as i32;
    Ok(Some((closed, total)))
}

pub fn run(db: &Database, crosslink_dir: &std::path::Path) -> Result<()> {
    let ready = db.list_ready_issues()?;

    if ready.is_empty() {
        println!("No issues ready to work on.");
        println!(
            "Use 'crosslink list' to see all issues or 'crosslink blocked' to see blocked issues."
        );
        return Ok(());
    }

    // Load lock state for filtering (best-effort, non-blocking)
    let locks_filter = load_locks_filter(crosslink_dir);

    // Score and sort issues
    let mut scored: Vec<ScoredIssue> = Vec::new();

    for issue in ready {
        // Skip subissues - we want to recommend parent issues or standalone issues
        if issue.parent_id.is_some() {
            continue;
        }

        // Skip issues locked by other agents
        if let Some((ref locks, ref my_agent_id)) = locks_filter {
            if locks.is_locked(issue.id) && !locks.is_locked_by(issue.id, my_agent_id) {
                continue;
            }
        }

        let priority_score = priority_weight(&issue.priority) * 100;
        let progress = calculate_progress(db, &issue)?;

        // Boost score for issues that are partially complete (finish what you started)
        let progress_bonus = match &progress {
            Some((closed, total)) if *closed > 0 && *closed < *total => 50,
            _ => 0,
        };

        let score = priority_score + progress_bonus;
        scored.push((issue, score, progress));
    }

    // Sort by score descending
    scored.sort_by(|a, b| b.1.cmp(&a.1));

    if scored.is_empty() {
        // All ready issues are subissues, show them instead
        let ready = db.list_ready_issues()?;
        if let Some(issue) = ready.first() {
            println!(
                "Next: {} [{}] {}",
                format_issue_id(issue.id),
                issue.priority,
                issue.title
            );
            if let Some(parent_id) = issue.parent_id {
                println!("       (subissue of {})", format_issue_id(parent_id));
            }
        } else {
            println!("No issues ready to work on.");
        }
        return Ok(());
    }

    // Recommend the top issue
    let (top, _score, progress) = &scored[0];
    println!(
        "Next: {} [{}] {}",
        format_issue_id(top.id),
        top.priority,
        top.title
    );

    if let Some((closed, total)) = progress {
        println!("       Progress: {}/{} subissues complete", closed, total);
    }

    if let Some(desc) = &top.description {
        if !desc.is_empty() {
            let preview: String = desc.chars().take(80).collect();
            let suffix = if desc.chars().count() > 80 { "..." } else { "" };
            println!("       {}{}", preview, suffix);
        }
    }

    println!();
    println!("Run: crosslink session work {}", top.id);

    // Show runners-up if any
    if scored.len() > 1 {
        println!();
        println!("Also ready:");
        for (issue, _score, progress) in scored.iter().skip(1).take(3) {
            let progress_str = match progress {
                Some((c, t)) => format!(" ({}/{})", c, t),
                None => String::new(),
            };
            println!(
                "  {} [{}] {}{}",
                format_issue_id(issue.id),
                issue.priority,
                issue.title,
                progress_str
            );
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;
    use tempfile::tempdir;

    fn setup_test_db() -> (Database, tempfile::TempDir) {
        let dir = tempdir().unwrap();
        let db_path = dir.path().join("test.db");
        let db = Database::open(&db_path).unwrap();
        (db, dir)
    }

    #[test]
    fn test_priority_weight_critical() {
        assert_eq!(priority_weight("critical"), 4);
    }

    #[test]
    fn test_priority_weight_high() {
        assert_eq!(priority_weight("high"), 3);
    }

    #[test]
    fn test_priority_weight_medium() {
        assert_eq!(priority_weight("medium"), 2);
    }

    #[test]
    fn test_priority_weight_low() {
        assert_eq!(priority_weight("low"), 1);
    }

    #[test]
    fn test_priority_weight_unknown() {
        assert_eq!(priority_weight("unknown"), 0);
    }

    #[test]
    fn test_run_no_issues() {
        let (db, dir) = setup_test_db();
        run(&db, dir.path()).unwrap();
        let ready = db.list_ready_issues().unwrap();
        assert!(ready.is_empty());
    }

    #[test]
    fn test_run_with_issues() {
        let (db, dir) = setup_test_db();
        let id = db.create_issue("Issue 1", None, "high").unwrap();

        run(&db, dir.path()).unwrap();
        let ready = db.list_ready_issues().unwrap();
        assert_eq!(ready.len(), 1);
        assert_eq!(ready[0].id, id);
    }

    #[test]
    fn test_run_prioritizes_higher() {
        let (db, dir) = setup_test_db();
        db.create_issue("Low priority", None, "low").unwrap();
        let critical_id = db
            .create_issue("Critical priority", None, "critical")
            .unwrap();
        db.create_issue("Medium priority", None, "medium").unwrap();

        run(&db, dir.path()).unwrap();
        // Verify the critical issue has the highest weight via the scoring function
        let ready = db.list_ready_issues().unwrap();
        assert_eq!(ready.len(), 3);
        let critical = ready.iter().find(|i| i.id == critical_id).unwrap();
        assert_eq!(critical.priority, "critical");
        // Critical should have highest weight
        assert_eq!(priority_weight("critical"), 4);
        assert!(priority_weight("critical") > priority_weight("low"));
        assert!(priority_weight("critical") > priority_weight("medium"));
    }

    #[test]
    fn test_calculate_progress_no_subissues() {
        let (db, _dir) = setup_test_db();
        let id = db.create_issue("Simple issue", None, "medium").unwrap();
        let issue = db.get_issue(id).unwrap().unwrap();

        let progress = calculate_progress(&db, &issue).unwrap();
        assert!(progress.is_none());
    }

    #[test]
    fn test_calculate_progress_with_subissues() {
        let (db, _dir) = setup_test_db();
        let parent_id = db.create_issue("Parent", None, "high").unwrap();
        let child1 = db
            .create_subissue(parent_id, "Child 1", None, "medium")
            .unwrap();
        db.create_subissue(parent_id, "Child 2", None, "medium")
            .unwrap();
        db.close_issue(child1).unwrap();

        let issue = db.get_issue(parent_id).unwrap().unwrap();
        let progress = calculate_progress(&db, &issue).unwrap();

        assert!(progress.is_some());
        let (closed, total) = progress.unwrap();
        assert_eq!(closed, 1);
        assert_eq!(total, 2);
    }

    #[test]
    fn test_run_skips_blocked() {
        let (db, dir) = setup_test_db();
        let blocker = db.create_issue("Blocker", None, "high").unwrap();
        let blocked = db.create_issue("Blocked", None, "critical").unwrap();
        db.add_dependency(blocked, blocker).unwrap();

        run(&db, dir.path()).unwrap();
        let ready = db.list_ready_issues().unwrap();
        assert!(
            !ready.iter().any(|i| i.id == blocked),
            "Blocked issue should not be in ready list"
        );
        assert!(
            ready.iter().any(|i| i.id == blocker),
            "Blocker should be in ready list"
        );
    }

    #[test]
    fn test_run_all_issues_closed() {
        let (db, dir) = setup_test_db();
        let id = db.create_issue("Done", None, "medium").unwrap();
        db.close_issue(id).unwrap();

        run(&db, dir.path()).unwrap();
        let ready = db.list_ready_issues().unwrap();
        assert!(
            ready.is_empty(),
            "Closed issues should not appear in ready list"
        );
    }

    proptest! {
        #[test]
        fn prop_priority_weight_valid(priority in "low|medium|high|critical") {
            let weight = priority_weight(&priority);
            prop_assert!((1..=4).contains(&weight));
        }

        #[test]
        fn prop_run_never_panics(count in 0usize..5) {
            let (db, dir) = setup_test_db();
            for i in 0..count {
                db.create_issue(&format!("Issue {}", i), None, "medium").unwrap();
            }
            let result = run(&db, dir.path());
            prop_assert!(result.is_ok());
        }
    }
}

// E-ana tablet — prune command: squash hub/knowledge branch history for storage efficiency
use anyhow::{bail, Context, Result};
use serde::Serialize;
use std::path::Path;
use std::process::Command;

use crate::knowledge::KnowledgeManager;
use crate::sync::SyncManager;

/// Options for the prune command.
pub struct PruneOpts {
    pub dry_run: bool,
    pub force: bool,
    pub keep_commits: usize,
    pub hub_only: bool,
    pub knowledge_only: bool,
}

/// Size stats for a branch before/after pruning.
#[derive(Debug, Serialize)]
struct BranchStats {
    branch: String,
    commits_before: usize,
    commits_after: usize,
}

/// Run a git command in the given directory, returning its output.
fn git_in_dir(dir: &Path, args: &[&str]) -> Result<std::process::Output> {
    let output = Command::new("git")
        .current_dir(dir)
        .args(args)
        .output()
        .with_context(|| format!("Failed to run git {:?} in {}", args, dir.display()))?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!(
            "git {:?} in {} failed: {}",
            args,
            dir.display(),
            stderr.trim()
        );
    }
    Ok(output)
}

/// Count the number of commits on the current branch in a worktree.
fn count_commits(cache_dir: &Path) -> Result<usize> {
    let output = git_in_dir(cache_dir, &["rev-list", "--count", "HEAD"])?;
    let count_str = String::from_utf8_lossy(&output.stdout).trim().to_string();
    count_str
        .parse::<usize>()
        .with_context(|| format!("Failed to parse commit count: {:?}", count_str))
}

/// Remove stale data files from the hub branch cache.
///
/// Cleans up old heartbeat files (V1 layout) and agent directories
/// for decommissioned agents (those with no events).
fn remove_stale_hub_data(cache_dir: &Path) -> Result<Vec<String>> {
    let mut removed = Vec::new();

    // Clean up old V1 heartbeat files
    let heartbeats_dir = cache_dir.join("heartbeats");
    if heartbeats_dir.is_dir() {
        for entry in std::fs::read_dir(&heartbeats_dir)? {
            let entry = entry?;
            if entry.file_type()?.is_file() {
                let name = entry.file_name().to_string_lossy().to_string();
                removed.push(format!("heartbeats/{}", name));
                std::fs::remove_file(entry.path())?;
            }
        }
        // Remove the directory if now empty
        if std::fs::read_dir(&heartbeats_dir)?.next().is_none() {
            std::fs::remove_dir(&heartbeats_dir)?;
        }
    }

    // Clean up agent directories for decommissioned agents
    // (those whose events.log is empty or missing)
    let agents_dir = cache_dir.join("agents");
    if agents_dir.is_dir() {
        for entry in std::fs::read_dir(&agents_dir)? {
            let entry = entry?;
            if !entry.file_type()?.is_dir() {
                continue;
            }
            let agent_dir = entry.path();
            let events_log = agent_dir.join("events.log");
            let has_events = events_log.exists()
                && std::fs::metadata(&events_log)
                    .map(|m| m.len() > 0)
                    .unwrap_or(false);

            if !has_events {
                let agent_name = entry.file_name().to_string_lossy().to_string();
                removed.push(format!("agents/{}/", agent_name));
                std::fs::remove_dir_all(&agent_dir)?;
            }
        }
    }

    Ok(removed)
}

/// Count stale data files without removing them (for dry-run).
fn count_stale_hub_data(cache_dir: &Path) -> Vec<String> {
    let mut stale = Vec::new();

    let heartbeats_dir = cache_dir.join("heartbeats");
    if heartbeats_dir.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&heartbeats_dir) {
            for entry in entries.flatten() {
                if entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
                    stale.push(format!(
                        "heartbeats/{}",
                        entry.file_name().to_string_lossy()
                    ));
                }
            }
        }
    }

    let agents_dir = cache_dir.join("agents");
    if agents_dir.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&agents_dir) {
            for entry in entries.flatten() {
                if !entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                    continue;
                }
                let events_log = entry.path().join("events.log");
                let has_events = events_log.exists()
                    && std::fs::metadata(&events_log)
                        .map(|m| m.len() > 0)
                        .unwrap_or(false);
                if !has_events {
                    stale.push(format!("agents/{}/", entry.file_name().to_string_lossy()));
                }
            }
        }
    }

    stale
}

/// Squash the history of a branch in a cache worktree.
///
/// Creates a new orphan commit (or keeps the last N commits) with the current
/// tree state, then force-updates the branch ref and force-pushes.
fn squash_branch(
    cache_dir: &Path,
    branch: &str,
    remote: &str,
    keep_commits: usize,
    dry_run: bool,
) -> Result<BranchStats> {
    let commits_before = count_commits(cache_dir)?;

    if commits_before <= keep_commits.max(1) {
        return Ok(BranchStats {
            branch: branch.to_string(),
            commits_before,
            commits_after: commits_before,
        });
    }

    if dry_run {
        let commits_after = keep_commits.max(1);
        return Ok(BranchStats {
            branch: branch.to_string(),
            commits_before,
            commits_after,
        });
    }

    let commits_after = if keep_commits <= 1 {
        // Squash everything into a single commit with the current tree.
        // 1. Stage all current content (ensures index matches worktree)
        git_in_dir(cache_dir, &["add", "-A"])?;

        // 2. Write the current index as a tree object
        let tree_output = git_in_dir(cache_dir, &["write-tree"])?;
        let tree_hash = String::from_utf8_lossy(&tree_output.stdout)
            .trim()
            .to_string();

        // 3. Create a root commit (no parent) with this tree
        let commit_output = Command::new("git")
            .current_dir(cache_dir)
            .args([
                "commit-tree",
                &tree_hash,
                "-m",
                &format!(
                    "prune: squash {} history to current state\n\nSquashed {} commit(s).",
                    branch, commits_before
                ),
            ])
            .output()
            .context("Failed to create squash commit")?;

        if !commit_output.status.success() {
            let stderr = String::from_utf8_lossy(&commit_output.stderr);
            bail!("git commit-tree failed: {}", stderr.trim());
        }

        let new_head = String::from_utf8_lossy(&commit_output.stdout)
            .trim()
            .to_string();

        // 4. Update the branch ref to the new root commit
        git_in_dir(
            cache_dir,
            &["update-ref", &format!("refs/heads/{}", branch), &new_head],
        )?;

        // 5. Reset HEAD to the new commit
        git_in_dir(cache_dir, &["reset", "--hard", &new_head])?;

        1
    } else {
        // Keep last N commits: rewrite history preserving recent commits.
        // Find the base commit (Nth from HEAD)
        let base_ref = format!("HEAD~{}", keep_commits);
        let base_hash_output = git_in_dir(cache_dir, &["rev-parse", &base_ref])?;
        let base_hash = String::from_utf8_lossy(&base_hash_output.stdout)
            .trim()
            .to_string();

        // Get the tree at the base commit
        let tree_output = git_in_dir(
            cache_dir,
            &["rev-parse", &format!("{}^{{tree}}", base_hash)],
        )?;
        let tree_hash = String::from_utf8_lossy(&tree_output.stdout)
            .trim()
            .to_string();

        // Create a new root commit with the base tree
        let commit_output = Command::new("git")
            .current_dir(cache_dir)
            .args([
                "commit-tree",
                &tree_hash,
                "-m",
                &format!(
                    "prune: squash {} history (kept last {} commits)\n\nSquashed {} commit(s).",
                    branch,
                    keep_commits,
                    commits_before - keep_commits
                ),
            ])
            .output()
            .context("Failed to create base squash commit")?;

        if !commit_output.status.success() {
            let stderr = String::from_utf8_lossy(&commit_output.stderr);
            bail!("git commit-tree failed: {}", stderr.trim());
        }

        let new_base = String::from_utf8_lossy(&commit_output.stdout)
            .trim()
            .to_string();

        // Save current tip
        let tip_output = git_in_dir(cache_dir, &["rev-parse", "HEAD"])?;
        let tip_hash = String::from_utf8_lossy(&tip_output.stdout)
            .trim()
            .to_string();

        // Detach, reset to new base, cherry-pick the kept commits
        git_in_dir(cache_dir, &["checkout", "--detach", "HEAD"])?;
        git_in_dir(cache_dir, &["reset", "--hard", &new_base])?;

        // Get list of commits to replay (oldest first)
        let range = format!("{}..{}", base_hash, tip_hash);
        let log_output = git_in_dir(cache_dir, &["rev-list", "--reverse", &range])?;
        let log_text = String::from_utf8_lossy(&log_output.stdout)
            .trim()
            .to_string();

        for commit_hash in log_text.lines() {
            if !commit_hash.is_empty() {
                git_in_dir(cache_dir, &["cherry-pick", commit_hash])?;
            }
        }

        // Update the branch ref to point to the new history
        let new_tip_output = git_in_dir(cache_dir, &["rev-parse", "HEAD"])?;
        let new_tip = String::from_utf8_lossy(&new_tip_output.stdout)
            .trim()
            .to_string();
        git_in_dir(
            cache_dir,
            &["update-ref", &format!("refs/heads/{}", branch), &new_tip],
        )?;
        git_in_dir(cache_dir, &["checkout", branch])?;

        keep_commits + 1 // base squash commit + kept commits
    };

    // Force-push the rewritten branch
    let refspec = format!("{}:{}", branch, branch);
    git_in_dir(cache_dir, &["push", "--force", remote, &refspec])?;

    Ok(BranchStats {
        branch: branch.to_string(),
        commits_before,
        commits_after,
    })
}

/// Entry point for `crosslink prune`.
pub fn run(crosslink_dir: &Path, opts: &PruneOpts, json: bool) -> Result<()> {
    if !opts.force && !opts.dry_run {
        eprintln!("Warning: This will rewrite branch history and force-push.");
        eprintln!("Use --force to confirm, or --dry-run to preview.");
        return Ok(());
    }

    let mut results: Vec<BranchStats> = Vec::new();
    let mut stale_removed: Vec<String> = Vec::new();

    // --- Hub branch ---
    if !opts.knowledge_only {
        let sync = SyncManager::new(crosslink_dir)?;
        sync.init_cache()?;
        sync.fetch()?;

        let cache_dir = sync.cache_path();

        if opts.dry_run {
            stale_removed = count_stale_hub_data(cache_dir);
        } else {
            let removed = remove_stale_hub_data(cache_dir)?;
            if !removed.is_empty() {
                // Stage and commit the cleanup
                let _ = git_in_dir(cache_dir, &["add", "-A"]);
                let has_changes = git_in_dir(cache_dir, &["diff", "--cached", "--quiet"]).is_err();
                if has_changes {
                    git_in_dir(cache_dir, &["commit", "-m", "prune: remove stale hub data"])?;
                }
                stale_removed = removed;
            }
        }

        let stats = squash_branch(
            cache_dir,
            "crosslink/hub",
            sync.remote(),
            opts.keep_commits,
            opts.dry_run,
        )?;
        results.push(stats);
    }

    // --- Knowledge branch ---
    if !opts.hub_only {
        let km = KnowledgeManager::new(crosslink_dir)?;
        if km.is_initialized() {
            km.init_cache()?;
            km.sync()?;

            let cache_dir = km.cache_path();
            let remote = crate::sync::read_tracker_remote(km.crosslink_dir());

            let stats = squash_branch(
                cache_dir,
                "crosslink/knowledge",
                &remote,
                opts.keep_commits,
                opts.dry_run,
            )?;
            results.push(stats);
        } else {
            eprintln!("Knowledge branch not initialized, skipping.");
        }
    }

    // --- Output ---
    if json {
        #[derive(Serialize)]
        struct PruneReport {
            branches: Vec<BranchStats>,
            stale_data_removed: Vec<String>,
            dry_run: bool,
        }
        let report = PruneReport {
            branches: results,
            stale_data_removed: stale_removed,
            dry_run: opts.dry_run,
        };
        println!("{}", serde_json::to_string_pretty(&report)?);
        return Ok(());
    }

    // Human-readable output
    if opts.dry_run {
        println!("Prune plan (dry run):\n");
    }

    for stats in &results {
        if stats.commits_before == stats.commits_after {
            println!(
                "  {} — {} commit(s), nothing to prune",
                stats.branch, stats.commits_before
            );
        } else {
            let verb = if opts.dry_run {
                "would remove"
            } else {
                "removed"
            };
            println!(
                "  {} — {} → {} commit(s) ({} {})",
                stats.branch,
                stats.commits_before,
                stats.commits_after,
                stats.commits_before - stats.commits_after,
                verb,
            );
        }
    }

    if !stale_removed.is_empty() {
        println!(
            "\n  Stale data {}: {} file(s)/dir(s)",
            if opts.dry_run { "to remove" } else { "removed" },
            stale_removed.len()
        );
        for item in &stale_removed {
            println!("    {}", item);
        }
    }

    if opts.dry_run {
        println!("\nRun with --force (without --dry-run) to proceed.");
    } else {
        println!("\nDone.");
    }

    Ok(())
}

use anyhow::Result;

use crate::db::Database;
use crate::shared_writer::SharedWriter;
use crate::utils::format_issue_id;

pub fn add(
    db: &Database,
    writer: Option<&SharedWriter>,
    issue_id: i64,
    related_id: i64,
) -> Result<()> {
    db.require_issue(issue_id)?;
    db.require_issue(related_id)?;

    if let Some(w) = writer {
        w.add_relation(db, issue_id, related_id)?;
        println!(
            "Linked {} ↔ {}",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    } else if db.add_relation(issue_id, related_id)? {
        println!(
            "Linked {} ↔ {}",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    } else {
        println!(
            "Issues {} and {} are already related",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    }

    Ok(())
}

pub fn remove(
    db: &Database,
    writer: Option<&SharedWriter>,
    issue_id: i64,
    related_id: i64,
) -> Result<()> {
    if let Some(w) = writer {
        w.remove_relation(db, issue_id, related_id)?;
        println!(
            "Unlinked {} ↔ {}",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    } else if db.remove_relation(issue_id, related_id)? {
        println!(
            "Unlinked {} ↔ {}",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    } else {
        println!(
            "No relation found between {} and {}",
            format_issue_id(issue_id),
            format_issue_id(related_id)
        );
    }

    Ok(())
}

pub fn list(db: &Database, issue_id: i64) -> Result<()> {
    db.require_issue(issue_id)?;

    let related = db.get_related_issues(issue_id)?;

    if related.is_empty() {
        println!("No related issues for {}", format_issue_id(issue_id));
        return Ok(());
    }

    println!("Related to {}:", format_issue_id(issue_id));
    for r in related {
        let status_marker = if r.status == "closed" { "✓" } else { " " };
        println!(
            "  {:<5} [{}] {:8} {}",
            format_issue_id(r.id),
            status_marker,
            r.priority,
            r.title
        );
    }

    Ok(())
}

