    // === Token usage tracking ===

    /// Record a token usage entry.
    #[allow(clippy::too_many_arguments)]
    pub fn create_token_usage(
        &self,
        agent_id: &str,
        session_id: Option<i64>,
        input_tokens: i64,
        output_tokens: i64,
        cache_read_tokens: Option<i64>,
        cache_creation_tokens: Option<i64>,
        model: &str,
        cost_estimate: Option<f64>,
    ) -> Result<i64> {
        let now = Utc::now().to_rfc3339();
        self.conn.execute(
            "INSERT INTO token_usage (agent_id, session_id, timestamp, input_tokens, output_tokens, cache_read_tokens, cache_creation_tokens, model, cost_estimate)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?9)",
            params![
                agent_id,
                session_id,
                now,
                input_tokens,
                output_tokens,
                cache_read_tokens,
                cache_creation_tokens,
                model,
                cost_estimate,
            ],
        )?;
        Ok(self.conn.last_insert_rowid())
    }

    /// Get a single token usage record by ID.
    pub fn get_token_usage(&self, id: i64) -> Result<Option<TokenUsage>> {
        let mut stmt = self.conn.prepare(
            "SELECT id, agent_id, session_id, timestamp, input_tokens, output_tokens,
                    cache_read_tokens, cache_creation_tokens, model, cost_estimate
             FROM token_usage WHERE id = ?1",
        )?;
        let mut rows = stmt
            .query_map(params![id], |row| {
                Ok(TokenUsage {
                    id: row.get(0)?,
                    agent_id: row.get(1)?,
                    session_id: row.get(2)?,
                    timestamp: parse_datetime(row.get::<_, String>(3)?),
                    input_tokens: row.get(4)?,
                    output_tokens: row.get(5)?,
                    cache_read_tokens: row.get(6)?,
                    cache_creation_tokens: row.get(7)?,
                    model: row.get(8)?,
                    cost_estimate: row.get(9)?,
                })
            })?
            .collect::<std::result::Result<Vec<_>, _>>()?;
        Ok(rows.pop())
    }

    /// List token usage records with optional filters.
    pub fn list_token_usage(
        &self,
        agent_id: Option<&str>,
        session_id: Option<i64>,
        model: Option<&str>,
        from: Option<&str>,
        to: Option<&str>,
        limit: Option<i64>,
    ) -> Result<Vec<TokenUsage>> {
        let mut sql = String::from(
            "SELECT id, agent_id, session_id, timestamp, input_tokens, output_tokens,
                    cache_read_tokens, cache_creation_tokens, model, cost_estimate
             FROM token_usage WHERE 1=1",
        );
        let mut param_values: Vec<Box<dyn rusqlite::types::ToSql>> = Vec::new();

        if let Some(aid) = agent_id {
            param_values.push(Box::new(aid.to_string()));
            sql.push_str(&format!(" AND agent_id = ?{}", param_values.len()));
        }
        if let Some(sid) = session_id {
            param_values.push(Box::new(sid));
            sql.push_str(&format!(" AND session_id = ?{}", param_values.len()));
        }
        if let Some(m) = model {
            param_values.push(Box::new(m.to_string()));
            sql.push_str(&format!(" AND model = ?{}", param_values.len()));
        }
        if let Some(f) = from {
            param_values.push(Box::new(f.to_string()));
            sql.push_str(&format!(" AND timestamp >= ?{}", param_values.len()));
        }
        if let Some(t) = to {
            param_values.push(Box::new(t.to_string()));
            sql.push_str(&format!(" AND timestamp <= ?{}", param_values.len()));
        }

        sql.push_str(" ORDER BY timestamp DESC");

        if let Some(lim) = limit {
            param_values.push(Box::new(lim));
            sql.push_str(&format!(" LIMIT ?{}", param_values.len()));
        }

        let param_refs: Vec<&dyn rusqlite::types::ToSql> =
            param_values.iter().map(|b| b.as_ref()).collect();

        let mut stmt = self.conn.prepare(&sql)?;
        let rows = stmt
            .query_map(param_refs.as_slice(), |row| {
                Ok(TokenUsage {
                    id: row.get(0)?,
                    agent_id: row.get(1)?,
                    session_id: row.get(2)?,
                    timestamp: parse_datetime(row.get::<_, String>(3)?),
                    input_tokens: row.get(4)?,
                    output_tokens: row.get(5)?,
                    cache_read_tokens: row.get(6)?,
                    cache_creation_tokens: row.get(7)?,
                    model: row.get(8)?,
                    cost_estimate: row.get(9)?,
                })
            })?
            .collect::<std::result::Result<Vec<_>, _>>()?;
        Ok(rows)
    }

    /// Get aggregated usage summary, optionally filtered by agent and time range.
    /// Groups by agent_id and model.
    pub fn get_usage_summary(
        &self,
        agent_id: Option<&str>,
        from: Option<&str>,
        to: Option<&str>,
    ) -> Result<Vec<UsageSummaryRow>> {
        let mut sql = String::from(
            "SELECT agent_id, model,
                    COUNT(*) as request_count,
                    SUM(input_tokens) as total_input_tokens,
                    SUM(output_tokens) as total_output_tokens,
                    COALESCE(SUM(cache_read_tokens), 0) as total_cache_read_tokens,
                    COALESCE(SUM(cache_creation_tokens), 0) as total_cache_creation_tokens,
                    COALESCE(SUM(cost_estimate), 0.0) as total_cost
             FROM token_usage WHERE 1=1",
        );
        let mut param_values: Vec<Box<dyn rusqlite::types::ToSql>> = Vec::new();

        if let Some(aid) = agent_id {
            param_values.push(Box::new(aid.to_string()));
            sql.push_str(&format!(" AND agent_id = ?{}", param_values.len()));
        }
        if let Some(f) = from {
            param_values.push(Box::new(f.to_string()));
            sql.push_str(&format!(" AND timestamp >= ?{}", param_values.len()));
        }
        if let Some(t) = to {
            param_values.push(Box::new(t.to_string()));
            sql.push_str(&format!(" AND timestamp <= ?{}", param_values.len()));
        }

        sql.push_str(" GROUP BY agent_id, model ORDER BY total_cost DESC");

        let param_refs: Vec<&dyn rusqlite::types::ToSql> =
            param_values.iter().map(|b| b.as_ref()).collect();

        let mut stmt = self.conn.prepare(&sql)?;
        let rows = stmt
            .query_map(param_refs.as_slice(), |row| {
                Ok(UsageSummaryRow {
                    agent_id: row.get(0)?,
                    model: row.get(1)?,
                    request_count: row.get(2)?,
                    total_input_tokens: row.get(3)?,
                    total_output_tokens: row.get(4)?,
                    total_cache_read_tokens: row.get(5)?,
                    total_cache_creation_tokens: row.get(6)?,
                    total_cost: row.get(7)?,
                })
            })?
            .collect::<std::result::Result<Vec<_>, _>>()?;
        Ok(rows)
    }
}

fn parse_datetime(s: String) -> DateTime<Utc> {
    DateTime::parse_from_rfc3339(&s)
        .map(|dt| dt.with_timezone(&Utc))
        .unwrap_or_else(|e| {
            eprintln!(
                "warning: failed to parse datetime '{}': {}, using current time",
                s, e
            );
            chrono::Utc::now()
        })
}

/// Maps a database row to an Issue struct.
/// Expects columns in order: id, title, description, status, priority, parent_id, created_at, updated_at, closed_at
fn session_from_row(row: &rusqlite::Row) -> rusqlite::Result<Session> {
    Ok(Session {
        id: row.get(0)?,
        started_at: parse_datetime(row.get::<_, String>(1)?),
        ended_at: row.get::<_, Option<String>>(2)?.map(parse_datetime),
        active_issue_id: row.get(3)?,
        handoff_notes: row.get(4)?,
        last_action: row.get(5)?,
        agent_id: row.get(6)?,
    })
}

fn issue_from_row(row: &rusqlite::Row) -> rusqlite::Result<Issue> {
    Ok(Issue {
        id: row.get(0)?,
        title: row.get(1)?,
        description: row.get(2)?,
        status: row.get(3)?,
        priority: row.get(4)?,
        parent_id: row.get(5)?,
        created_at: parse_datetime(row.get::<_, String>(6)?),
        updated_at: parse_datetime(row.get::<_, String>(7)?),
        closed_at: row.get::<_, Option<String>>(8)?.map(parse_datetime),
    })
}

