                agent_id: "a".to_string(),
                stale: false
            },
            LockStatus::LockedByOther {
                agent_id: "b".to_string(),
                stale: false
            }
        );
        // stale flag participates in equality
        assert_ne!(
            LockStatus::LockedByOther {
                agent_id: "a".to_string(),
                stale: false
            },
            LockStatus::LockedByOther {
                agent_id: "a".to_string(),
