    /// Test merge_small_partitions: prev is big (>= MIN), part is big — both pushed separately.
    #[test]
    fn test_merge_small_partitions_big_prev_big_part() {
        // Three partitions: one small (< MIN_PARTITION_LINES), one that makes carry big, one big.
        // After sort: small(50), medium(150), big(300).
        // Step 1: small(50) → carry = small
        // Step 2: carry(50) + medium(150) = 200 >= MIN → merged = [200-merged]
        // Step 3: big(300) → carry is None, 300 >= MIN → merged = [200-merged, big]
        let partitions = vec![
            Partition {
                label: "big".to_string(),
                files: vec![PathBuf::from("big.rs")],
                line_count: 300,
            },
            Partition {
                label: "small".to_string(),
                files: vec![PathBuf::from("small.rs")],
                line_count: 50,
            },
            Partition {
                label: "medium".to_string(),
                files: vec![PathBuf::from("medium.rs")],
                line_count: 150,
            },
        ];
        let result = merge_small_partitions(partitions);
        assert_eq!(result.len(), 2);
    }

    /// Test merge_small_partitions: prev (carry) >= MIN_PARTITION_LINES, new part also >= MIN.
    /// This exercises the else branch (line 733) where both are pushed separately.
    #[test]
    fn test_merge_small_partitions_carry_becomes_big_then_big_part() {
        // Four partitions: two small ones that merge to >= MIN, then two big ones.
        // After sort: tiny(50), tiny2(60), big1(250), big2(300).
        // Step 1: tiny(50) → carry = tiny
        // Step 2: carry(50) + tiny2(60) = 110 < MIN → carry = merged(110)
        // Step 3: carry(110) + big1(250) → carry < MIN → merge → 360 >= MIN → push merged(360)
        // Step 4: big2(300) → carry is None, 300 >= MIN → push big2(300)
        let partitions = vec![
            Partition {
                label: "big2".to_string(),
                files: vec![PathBuf::from("big2.rs")],
                line_count: 300,
            },
            Partition {
                label: "big1".to_string(),
                files: vec![PathBuf::from("big1.rs")],
                line_count: 250,
            },
            Partition {
                label: "tiny".to_string(),
                files: vec![PathBuf::from("tiny.rs")],
                line_count: 50,
            },
            Partition {
                label: "tiny2".to_string(),
                files: vec![PathBuf::from("tiny2.rs")],
                line_count: 60,
            },
        ];
        let result = merge_small_partitions(partitions);
        assert_eq!(result.len(), 2);
    }

    /// Test merge_small_partitions: leftover carry absorbed into last merged partition.
    #[test]
    fn test_merge_small_partitions_leftover_carry_absorbed() {
        // Two partitions: one big, one small. After sort: small(50), big(300).
        // Step 1: small(50) → carry = small
        // Step 2: carry(50) + big(300) → carry < MIN → merge → 350 → push
        // No leftover carry.
        //
        // To get leftover: three parts where the last is small.
        // big(300), medium(250), tiny(50). After sort: tiny(50), medium(250), big(300).
        // Step 1: tiny(50) → carry = tiny
        // Step 2: carry(50) + medium(250) → carry < MIN → merge(300) → push
        // Step 3: big(300) → carry = None, push big(300)
        // No leftover.
        //
        // For carry at end: big(300), tiny1(50), tiny2(60). Sorted: tiny1(50), tiny2(60), big(300).
        // Step 1: tiny1(50) → carry
        // Step 2: carry(50) + tiny2(60) → 110 < MIN → carry = merged(110)
        // Step 3: carry(110) + big(300) → carry < MIN → merge(410) → push
        // No leftover.
        //
        // To get leftover carry absorbed: prev >= MIN AND part < MIN makes part carry, then loop ends.
        // Need: big(300), medium(250), tiny(50). Sorted: tiny(50), medium(250), big(300).
        // Nope, that merges tiny+medium.
        //
        // Actually to hit line 748: we need carry left at the end AND merged is non-empty.
        // Three items: big1(250), big2(300), small(50). Sorted: small(50), big1(250), big2(300).
        // Step 1: small(50) → carry
        // Step 2: carry(50) + big1(250) → carry < MIN → merge(300) → push merged(300)
        // Step 3: big2(300) → carry is None → push big2(300)
        // No leftover carry.
        //
        // Hmm. To get carry at the end with merged non-empty:
        // big(300), huge(400), small(50). Sort: small(50), big(300), huge(400).
        // Step 1: small(50) → carry
        // Step 2: carry(50) + big(300) → 50 < MIN → merge(350) → push
        // Step 3: huge(400) → carry None → push
        // No carry.
        //
        // I think we need carry to be set at end. That requires the LAST partition in sorted order
        // to be small, but sorted is by line_count ascending, so last = biggest. We'd need all to be < MIN.
        // Three: a(50), b(60), c(80). All < MIN. Sorted: a(50), b(60), c(80).
        // Step 1: a(50) → carry
        // Step 2: carry(50) + b(60) → 110, 50 < MIN → merge(110) → carry(110)
        // Step 3: carry(110) + c(80) → 190, 110 < MIN → merge(190) → carry(190)
        // End: leftover = carry(190), merged is empty → else branch (push leftover)
        //
        // For line 748 we need merged to be NON-empty when leftover exists.
        // Four: a(50), b(60), c(100), d(30). Sorted: d(30), a(50), b(60), c(100).
        // Step 1: d(30) → carry
        // Step 2: carry(30) + a(50) → 80, 30 < MIN → merge(80) → carry(80)
        // Step 3: carry(80) + b(60) → 140, 80 < MIN → merge(140) → carry(140)
        // Step 4: carry(140) + c(100) → 240, 140 < MIN → merge(240) → push merged(240)
        // End: no carry. Hmm.
        //
        // Need: prev >= MIN_PARTITION_LINES AND part < MIN → part becomes carry (line 735-736).
        // Then loop ends with carry set.
        // This means: prev (from carry merge) is >= 200, and next part is < 200 but is the LAST item.
        // But items are sorted ascending... so the last item is the biggest. For it to be < 200,
        // all items must be < 200. Let's try:
        // a(150), b(60), c(50). Sorted: c(50), b(60), a(150).
        // Step 1: c(50) → carry
        // Step 2: carry(50) + b(60) → 110, 50 < MIN → merge(110) → carry(110)
        // Step 3: carry(110) + a(150) → 260, 110 < MIN → merge(260) → push
        // No carry left.
        //
        // Actually the else branch at 733 requires BOTH prev >= MIN AND (prev+part >= MIN).
        // carry can only be set from a small partition or a merged-small partition.
        // If prev (carry) < MIN, we always enter the `if` branch at 714-715.
        // So the else branch is only reachable when carry >= MIN.
        // carry can become >= MIN if it was merged from smaller parts. But then prev >= MIN.
        // For part to become carry (line 735-736), part < MIN. But the loop processes items
        // sorted ascending. If we reach the else branch, the current part must be < MIN even
        // though it comes after prev in sorted order. But sorted ascending means part >= prev
        // in line_count. If prev >= MIN and part < MIN, that's a contradiction since part
        // should be bigger.
        //
        // Wait — prev is from carry, not from the sorted sequence. carry tracks a merged-so-far value.
        // So: carry could be 250 (merged from smaller), and the next sorted item could be the
        // biggest remaining item, say 300. Then prev >= MIN (250) AND part >= MIN (300).
        // Both pushed separately — that's line 734 + 738 (prev pushed, part pushed).
        //
        // So the "part < MIN" at line 735 would be hit if somehow a later sorted item is < MIN.
        // But sorted ascending means later items are bigger. So line 735 is unreachable in
        // the current code! The only way is if MIN_PARTITION_LINES changes between iterations
        // (it doesn't).
        //
        // Lines 735-736 may be unreachable. But line 734 and 738 ARE reachable.
        // Let me test the case where prev >= MIN AND part >= MIN (both pushed).
        let partitions = vec![
            Partition {
                label: "a".to_string(),
                files: vec![PathBuf::from("a.rs")],
                line_count: 150,
            },
            Partition {
                label: "b".to_string(),
                files: vec![PathBuf::from("b.rs")],
                line_count: 100,
            },
            Partition {
                label: "c".to_string(),
                files: vec![PathBuf::from("c.rs")],
                line_count: 250,
            },
        ];
        // Sorted: b(100), a(150), c(250).
        // Step 1: b(100) → carry
        // Step 2: carry(100) + a(150) → 100 < MIN → merge(250) → push merged(250)
        // Step 3: c(250) → carry None → push c(250)
        let result = merge_small_partitions(partitions);
        assert_eq!(result.len(), 2);
    }
}

//! Handlers for agent monitoring and lock endpoints.
//!
//! Implements:
//! - `GET /api/v1/agents` — list all agents with latest heartbeat and status
//! - `GET /api/v1/agents/:id` — single agent detail with heartbeat history, locks, kickoff status
//! - `GET /api/v1/agents/:id/status` — kickoff status for a specific agent
//! - `GET /api/v1/locks` — all current locks
//! - `GET /api/v1/locks/stale` — stale locks with age

use std::path::{Path, PathBuf};
use std::process::Command;

use axum::{
    extract::{Path as AxumPath, State},
    http::StatusCode,
    response::Json,
};
use chrono::{Duration, Utc};
use serde::Serialize;
use serde_json::{json, Value};

use crate::server::{
    state::AppState,
    types::{AgentDetail, AgentStatus, AgentSummary, ApiError, LockEntry},
};
use crate::sync::SyncManager;

// ---------------------------------------------------------------------------
// Staleness thresholds
// ---------------------------------------------------------------------------

/// Heartbeat age below which an agent is considered "active".
const ACTIVE_THRESHOLD_SECS: i64 = 5 * 60;
/// Heartbeat age above which an agent is considered "stale" (between this and
/// ACTIVE_THRESHOLD is "idle").
const IDLE_THRESHOLD_SECS: i64 = 30 * 60;

// ---------------------------------------------------------------------------
// Helper types
// ---------------------------------------------------------------------------

/// Response for `GET /api/v1/agents/:id/status`.
#[derive(Debug, Serialize)]
pub struct AgentStatusResponse {
    pub agent_id: String,
    /// Content of `.kickoff-status` file, or a derived string when not present.
    pub kickoff_status: String,
    /// Absolute path of the agent's git worktree, if discoverable.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub worktree_path: Option<String>,
    /// Whether the agent's tmux session is currently running.
    pub tmux_session_active: bool,
}

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

/// Classify an agent's status from its heartbeat age in seconds.
fn classify_status(age_secs: i64) -> AgentStatus {
    if age_secs < ACTIVE_THRESHOLD_SECS {
        AgentStatus::Active
    } else if age_secs < IDLE_THRESHOLD_SECS {
        AgentStatus::Idle
    } else {
        AgentStatus::Stale
    }
}

/// Scan `.worktrees/` for a directory whose name matches the given `agent_id`.
///
/// Matching rules (tried in order):
/// 1. Exact slug match.
/// 2. The agent_id contains the slug.
/// 3. The slug contains the agent_id.
fn find_worktree_for_agent(root: &Path, agent_id: &str) -> Option<PathBuf> {
    let worktrees_dir = root.join(".worktrees");
    if !worktrees_dir.is_dir() {
        return None;
    }
    std::fs::read_dir(&worktrees_dir)
        .ok()?
        .filter_map(|e| e.ok())
        .filter(|e| e.file_type().map(|t| t.is_dir()).unwrap_or(false))
        .find(|e| {
            let slug = e.file_name().to_string_lossy().to_string();
            agent_id == slug || agent_id.contains(&slug) || slug.contains(agent_id)
        })
        .map(|e| e.path())
}

/// Read the current git branch from a linked worktree directory.
///
/// In a git linked worktree the `.git` entry is a *file* (not a directory)
/// containing `gitdir: <path>`.  We resolve that path and read the `HEAD`
/// file from it.
fn read_worktree_branch(worktree: &Path) -> Option<String> {
    let git_entry = worktree.join(".git");
    let head_content = if git_entry.is_file() {
        // Linked worktree: .git is a file with "gitdir: <path>"
        let git_file = std::fs::read_to_string(&git_entry).ok()?;
        let gitdir = git_file.strip_prefix("gitdir: ")?.trim();
        let head_path = PathBuf::from(gitdir).join("HEAD");
        std::fs::read_to_string(&head_path).ok()?
    } else if git_entry.is_dir() {
        // Bare-style: .git/HEAD
        std::fs::read_to_string(git_entry.join("HEAD")).ok()?
    } else {
        return None;
    };

    // HEAD contains either "ref: refs/heads/<branch>" or a detached SHA.
    head_content
        .strip_prefix("ref: refs/heads/")
        .map(|b| b.trim().to_string())
}

/// Return `true` if the named tmux session is currently running.
fn tmux_session_exists(name: &str) -> bool {
    Command::new("tmux")
        .args(["has-session", "-t", name])
        .output()
        .map(|o| o.status.success())
        .unwrap_or(false)
}

/// Derive the expected tmux session name for a worktree slug.
///
/// Mirrors the logic in `commands::kickoff::tmux_session_name`.
fn agent_tmux_session(agent_id: &str) -> String {
    // Strip common prefixes used in agent IDs / branch names
    let slug = agent_id
        .strip_prefix("feature/")
        .or_else(|| agent_id.strip_prefix("feat-"))
        .unwrap_or(agent_id);
    // Split on "--": agent IDs are "<parent>--<slug>"; we want the last part
    let wt_slug = slug.rsplit("--").next().unwrap_or(slug);
    let raw = format!("feat-{}", wt_slug);
    let sanitized: String = raw
        .chars()
        .map(|c| if c == '.' || c == ':' { '-' } else { c })
        .collect();
    if sanitized.len() > 50 {
        sanitized[..50].to_string()
    } else {
        sanitized
    }
}

/// Build an internal-server-error response from an error.
fn internal_error(context: &str, e: impl std::fmt::Display) -> (StatusCode, Json<ApiError>) {
    (
        StatusCode::INTERNAL_SERVER_ERROR,
        Json(ApiError {
            error: context.to_string(),
            detail: Some(e.to_string()),
        }),
    )
}

/// Build a not-found response.
fn not_found(msg: impl Into<String>) -> (StatusCode, Json<ApiError>) {
    (
        StatusCode::NOT_FOUND,
        Json(ApiError {
            error: "not found".to_string(),
            detail: Some(msg.into()),
        }),
    )
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

/// `GET /api/v1/agents` — list all known agents with latest heartbeat and status.
pub async fn list_agents(
    State(state): State<AppState>,
) -> Result<Json<Value>, (StatusCode, Json<ApiError>)> {
    let sync = SyncManager::new(&state.crosslink_dir)
        .map_err(|e| internal_error("Failed to initialise SyncManager", e))?;

    let heartbeats = sync
        .read_heartbeats_auto()
        .map_err(|e| internal_error("Failed to read heartbeats", e))?;

    let locks_file = sync
        .read_locks_auto()
        .unwrap_or_else(|_| crate::locks::LocksFile::empty());

    let now = Utc::now();
    let root = state
        .crosslink_dir
        .parent()
        .map(|p| p.to_path_buf())
        .unwrap_or_else(|| state.crosslink_dir.clone());

    let agents: Vec<AgentSummary> = heartbeats
        .into_iter()
        .map(|hb| {
            let age_secs = now
                .signed_duration_since(hb.last_heartbeat)
                .max(Duration::zero())
                .num_seconds();
            let status = classify_status(age_secs);
            let agent_locks = locks_file.agent_locks(&hb.agent_id);
            let worktree = find_worktree_for_agent(&root, &hb.agent_id);
            let branch = worktree.as_deref().and_then(read_worktree_branch);
            let worktree_path = worktree.map(|p| p.to_string_lossy().into_owned());
            AgentSummary {
                agent_id: hb.agent_id,
                machine_id: hb.machine_id,
                description: None,
                status,
                last_heartbeat: hb.last_heartbeat,
                active_issue_id: hb.active_issue_id,
                branch,
                worktree_path,
                locks: agent_locks,
            }
        })
        .collect();

    let total = agents.len();
    Ok(Json(json!({
        "items": agents,
        "total": total
    })))
}

/// `GET /api/v1/agents/:id` — detailed view of a single agent.
pub async fn get_agent(
    State(state): State<AppState>,
    AxumPath(agent_id): AxumPath<String>,
) -> Result<Json<AgentDetail>, (StatusCode, Json<ApiError>)> {
    let sync = SyncManager::new(&state.crosslink_dir)
        .map_err(|e| internal_error("Failed to initialise SyncManager", e))?;

    let heartbeats = sync
        .read_heartbeats_auto()
        .map_err(|e| internal_error("Failed to read heartbeats", e))?;

    let hb = heartbeats
        .into_iter()
        .find(|h| h.agent_id == agent_id)
        .ok_or_else(|| not_found(format!("No heartbeat found for agent '{}'", agent_id)))?;

    let locks_file = sync
        .read_locks_auto()
        .unwrap_or_else(|_| crate::locks::LocksFile::empty());

    let now = Utc::now();
    let age_secs = now
        .signed_duration_since(hb.last_heartbeat)
        .max(Duration::zero())
        .num_seconds();
    let status = classify_status(age_secs);
    let agent_locks = locks_file.agent_locks(&hb.agent_id);

    let root = state
        .crosslink_dir
        .parent()
        .map(|p| p.to_path_buf())
        .unwrap_or_else(|| state.crosslink_dir.clone());

    let worktree = find_worktree_for_agent(&root, &hb.agent_id);
    let branch = worktree.as_deref().and_then(read_worktree_branch);
    let worktree_path = worktree.as_ref().map(|p| p.to_string_lossy().into_owned());

    let kickoff_status = worktree.as_ref().and_then(|wt| {
        let path = wt.join(".kickoff-status");
        std::fs::read_to_string(path)
            .ok()
            .map(|s| s.trim().to_string())
    });

    // The hub only stores the latest heartbeat per agent; expose it as a
    // single-entry history.  A future version can persist a rolling log.
    let heartbeat_history = vec![hb.last_heartbeat];

    let summary = AgentSummary {
        agent_id: hb.agent_id,
        machine_id: hb.machine_id,
        description: None,
        status,
        last_heartbeat: hb.last_heartbeat,
        active_issue_id: hb.active_issue_id,
        branch,
        worktree_path,
        locks: agent_locks,
    };

    Ok(Json(AgentDetail {
        summary,
        heartbeat_history,
        kickoff_status,
    }))
}

/// `GET /api/v1/agents/:id/status` — kickoff status for a specific agent.
///
/// Reads the `.kickoff-status` file from the agent's worktree (if present)
/// and reports whether the agent's tmux session is still running.
pub async fn get_agent_status(
    State(state): State<AppState>,
    AxumPath(agent_id): AxumPath<String>,
) -> Result<Json<AgentStatusResponse>, (StatusCode, Json<ApiError>)> {
    let root = state
        .crosslink_dir
        .parent()
        .map(|p| p.to_path_buf())
        .unwrap_or_else(|| state.crosslink_dir.clone());

    let worktree = find_worktree_for_agent(&root, &agent_id);

    let kickoff_status = match &worktree {
        Some(wt) => {
            let path = wt.join(".kickoff-status");
            if path.exists() {
                std::fs::read_to_string(&path)
                    .unwrap_or_default()
                    .trim()
                    .to_string()
            } else {
                "running".to_string()
            }
        }
        None => "unknown".to_string(),
    };

    let session_name = agent_tmux_session(&agent_id);
    let tmux_session_active = tmux_session_exists(&session_name);

    Ok(Json(AgentStatusResponse {
        agent_id,
        kickoff_status,
        worktree_path: worktree.map(|p| p.to_string_lossy().into_owned()),
        tmux_session_active,
    }))
}

/// `GET /api/v1/locks` — all active locks with derived metadata.
pub async fn list_locks(
    State(state): State<AppState>,
) -> Result<Json<Value>, (StatusCode, Json<ApiError>)> {
    let sync = SyncManager::new(&state.crosslink_dir)
        .map_err(|e| internal_error("Failed to initialise SyncManager", e))?;

    let locks_file = sync
        .read_locks_auto()
        .map_err(|e| internal_error("Failed to read locks", e))?;

    let now = Utc::now();
    let stale_timeout = Duration::minutes(locks_file.settings.stale_lock_timeout_minutes as i64);

    let entries: Vec<LockEntry> = locks_file
        .locks
        .iter()
        .filter_map(|(id_str, lock)| {
            let issue_id = id_str.parse::<i64>().ok()?;
            let age = now
                .signed_duration_since(lock.claimed_at)
                .max(Duration::zero());
            let is_stale = age >= stale_timeout;
            Some(LockEntry {
                issue_id,
                agent_id: lock.agent_id.clone(),
                branch: lock.branch.clone(),
                claimed_at: lock.claimed_at,
                signed_by: lock.signed_by.clone(),
                age_seconds: age.num_seconds(),
                is_stale,
            })
        })
        .collect();

    let total = entries.len();
    Ok(Json(json!({
        "items": entries,
        "total": total
    })))
}

/// `GET /api/v1/locks/stale` — locks whose holding agent has gone stale.
///
/// Uses `SyncManager::find_stale_locks_with_age` which accounts for the
/// agent's heartbeat freshness, not just lock claimed-at time.
pub async fn list_stale_locks(
    State(state): State<AppState>,
) -> Result<Json<Value>, (StatusCode, Json<ApiError>)> {
    let sync = SyncManager::new(&state.crosslink_dir)
        .map_err(|e| internal_error("Failed to initialise SyncManager", e))?;

    let stale = sync
        .find_stale_locks_with_age()
        .map_err(|e| internal_error("Failed to read stale locks", e))?;

    // Re-read the full locks file to get branch/claimed_at/signed_by.
    let locks_file = sync
        .read_locks_auto()
        .unwrap_or_else(|_| crate::locks::LocksFile::empty());

    let now = Utc::now();
    let entries: Vec<LockEntry> = stale
        .into_iter()
        .filter_map(|(issue_id, _agent_id_from_stale, _age_minutes)| {
            let lock = locks_file.get_lock(issue_id)?;
            let age_secs = now
                .signed_duration_since(lock.claimed_at)
                .max(Duration::zero())
                .num_seconds();
            Some(LockEntry {
                issue_id,
                agent_id: lock.agent_id.clone(),
                branch: lock.branch.clone(),
                claimed_at: lock.claimed_at,
                signed_by: lock.signed_by.clone(),
                age_seconds: age_secs,
                is_stale: true,
            })
        })
        .collect();

    let total = entries.len();
    Ok(Json(json!({
        "items": entries,
        "total": total
    })))
}

