        assert_eq!(body["hub_initialized"], true);
        assert_eq!(body["hub_branch"], "crosslink/hub");
        // No locks seeded
        assert_eq!(body["active_lock_count"], 0);
        assert_eq!(body["stale_lock_count"], 0);
    }

    #[tokio::test]
    async fn test_sync_fetch_with_hub_initialized_offline() {
        // When hub is initialized but remote is unreachable (offline env),
        // the fetch attempt should not panic — it either succeeds or returns
        // an internal error. We only assert that the request completes.
        let (app, _dir) = test_app_with_hub();
        let resp = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/v1/sync/fetch")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        // Either 200 (fetch ran, possibly offline OK) or 500 (git error)
        // — we just verify the request doesn't return 409 Conflict.
        assert_ne!(resp.status(), StatusCode::CONFLICT);
    }

    #[tokio::test]
    async fn test_sync_push_with_hub_initialized_offline() {
        // Similar to fetch — verifies the push handler exercises the
        // hub-initialized branch and completes without panicking.
        let (app, _dir) = test_app_with_hub();
        let resp = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/v1/sync/push")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        // Either 200 (push ran) or 500 (git error — no remote configured)
        assert_ne!(resp.status(), StatusCode::CONFLICT);
    }

    #[test]
    fn test_internal_error_helper() {
        let (status, json) = super::internal_error("sync failed", "some error");
        assert_eq!(status, StatusCode::INTERNAL_SERVER_ERROR);
        assert_eq!(json.error, "sync failed");
        assert_eq!(json.detail.as_deref(), Some("some error"));
    }

    #[test]
    fn test_push_hub_cache_no_git_repo_bails() {
        // Call push_hub_cache with a SyncManager pointing at a temp dir
        // that has no git repo — the git push will fail.
        let dir = tempfile::tempdir().unwrap();
        let crosslink_dir = dir.path().join(".crosslink");
        let hub_cache = crosslink_dir.join(".hub-cache");
        std::fs::create_dir_all(&hub_cache).unwrap();

        let sm = crate::sync::SyncManager::new(&crosslink_dir).unwrap();
        // push_hub_cache runs `git push` which will fail in a non-git directory.
        // It should return an error (not panic).
        let result = super::push_hub_cache(&sm);
        // Either Ok (git offline path) or Err (git command failed) — not panic.
        let _ = result;
    }
}

//! Handlers for token usage tracking endpoints.
//!
//! Implements:
//! - `GET  /api/v1/usage`         — list token usage records with optional filters
//! - `POST /api/v1/usage`         — record a new token usage entry
//! - `GET  /api/v1/usage/summary` — aggregated usage grouped by agent and model

use axum::{
    extract::{Query, State},
    http::StatusCode,
    response::Json,
};

use crate::server::{
    state::AppState,
    types::{
        ApiError, CreateTokenUsageRequest, TokenUsageListQuery, TokenUsageListResponse,
        TokenUsageSummaryQuery, TokenUsageSummaryResponse,
    },
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

fn internal_error(context: &str, e: impl std::fmt::Display) -> (StatusCode, Json<ApiError>) {
    (
        StatusCode::INTERNAL_SERVER_ERROR,
        Json(ApiError {
            error: context.to_string(),
            detail: Some(e.to_string()),
        }),
    )
}

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------

/// `GET /api/v1/usage` — list token usage records.
///
/// Supports optional query parameters: `agent_id`, `session_id`, `model`,
/// `from`, `to` (ISO 8601 timestamps), and `limit`.
pub async fn list_usage(
    State(state): State<AppState>,
    Query(params): Query<TokenUsageListQuery>,
) -> Result<Json<TokenUsageListResponse>, (StatusCode, Json<ApiError>)> {
    let db = state.db();

    let items = db
        .list_token_usage(
            params.agent_id.as_deref(),
            params.session_id,
            params.model.as_deref(),
            params.from.as_deref(),
            params.to.as_deref(),
            params.limit,
        )
        .map_err(|e| internal_error("Failed to list token usage", e))?;

    let total = items.len();
    Ok(Json(TokenUsageListResponse { items, total }))
}

/// `POST /api/v1/usage` — record a new token usage entry.
///
/// Body: `CreateTokenUsageRequest` JSON.
/// Returns the created `TokenUsage` record.
pub async fn create_usage(
    State(state): State<AppState>,
    Json(body): Json<CreateTokenUsageRequest>,
) -> Result<(StatusCode, Json<crate::models::TokenUsage>), (StatusCode, Json<ApiError>)> {
    let db = state.db();

    let id = db
        .create_token_usage(
            &body.agent_id,
            body.session_id,
            body.input_tokens,
            body.output_tokens,
            body.cache_read_tokens,
            body.cache_creation_tokens,
            &body.model,
            body.cost_estimate,
        )
        .map_err(|e| internal_error("Failed to create token usage", e))?;

    let usage = db
        .get_token_usage(id)
        .map_err(|e| internal_error("Failed to fetch new token usage", e))?
        .ok_or_else(|| internal_error("Token usage created but not found", format!("id={id}")))?;

    Ok((StatusCode::CREATED, Json(usage)))
}

/// `GET /api/v1/usage/summary` — aggregated usage grouped by agent and model.
///
/// Supports optional query parameters: `agent_id`, `from`, `to`.
pub async fn usage_summary(
    State(state): State<AppState>,
    Query(params): Query<TokenUsageSummaryQuery>,
) -> Result<Json<TokenUsageSummaryResponse>, (StatusCode, Json<ApiError>)> {
    let db = state.db();

    let items = db
        .get_usage_summary(
            params.agent_id.as_deref(),
            params.from.as_deref(),
            params.to.as_deref(),
        )
        .map_err(|e| internal_error("Failed to get usage summary", e))?;

    let total_input_tokens: i64 = items.iter().map(|r| r.total_input_tokens).sum();
    let total_output_tokens: i64 = items.iter().map(|r| r.total_output_tokens).sum();
    let total_cost: f64 = items.iter().map(|r| r.total_cost).sum();

    Ok(Json(TokenUsageSummaryResponse {
        items,
        total_input_tokens,
        total_output_tokens,
        total_cost,
    }))
}

