        assert!(!signers.add_entry(AllowedSignerEntry {
            principal: "m1@crosslink".to_string(),
            public_key: "ssh-ed25519 BBBB".to_string(),
            metadata_comment: None,
        }));
        assert_eq!(signers.entries.len(), 1);
