//! Token usage parsing and cost estimation.
//!
//! Provides utilities for:
//! - Parsing token usage data from Claude API response metadata
//! - Estimating costs based on model pricing
//! - Extracting usage from kickoff report JSON

use serde::Deserialize;

/// Raw token usage data as reported by the Claude API.
#[derive(Debug, Clone, Deserialize)]
pub struct RawTokenUsage {
    pub input_tokens: i64,
    pub output_tokens: i64,
    #[serde(default)]
    pub cache_read_input_tokens: Option<i64>,
    #[serde(default)]
    pub cache_creation_input_tokens: Option<i64>,
}

/// A parsed token usage record ready for database insertion.
#[derive(Debug, Clone)]
pub struct ParsedUsage {
    pub agent_id: String,
    pub session_id: Option<i64>,
    pub input_tokens: i64,
    pub output_tokens: i64,
    pub cache_read_tokens: Option<i64>,
    pub cache_creation_tokens: Option<i64>,
    pub model: String,
    pub cost_estimate: Option<f64>,
}

/// Model pricing per million tokens (input, output).
/// Based on publicly available Anthropic pricing as of 2025.
struct ModelPricing {
    input_per_mtok: f64,
    output_per_mtok: f64,
    cache_read_per_mtok: f64,
    cache_creation_per_mtok: f64,
}

fn get_pricing(model: &str) -> Option<ModelPricing> {
    // Normalize model name for matching
    let m = model.to_lowercase();
    if m.contains("opus") {
        Some(ModelPricing {
            input_per_mtok: 15.0,
            output_per_mtok: 75.0,
            cache_read_per_mtok: 1.5,
            cache_creation_per_mtok: 18.75,
        })
    } else if m.contains("sonnet") {
        Some(ModelPricing {
            input_per_mtok: 3.0,
            output_per_mtok: 15.0,
            cache_read_per_mtok: 0.3,
            cache_creation_per_mtok: 3.75,
        })
    } else if m.contains("haiku") {
        Some(ModelPricing {
            input_per_mtok: 0.80,
            output_per_mtok: 4.0,
            cache_read_per_mtok: 0.08,
            cache_creation_per_mtok: 1.0,
        })
    } else {
        None
    }
}

/// Estimate cost in USD for a token usage record.
pub fn estimate_cost(
    model: &str,
    input_tokens: i64,
    output_tokens: i64,
    cache_read_tokens: Option<i64>,
    cache_creation_tokens: Option<i64>,
) -> Option<f64> {
    let pricing = get_pricing(model)?;
    let input_cost = (input_tokens as f64 / 1_000_000.0) * pricing.input_per_mtok;
    let output_cost = (output_tokens as f64 / 1_000_000.0) * pricing.output_per_mtok;
    let cache_read_cost =
        (cache_read_tokens.unwrap_or(0) as f64 / 1_000_000.0) * pricing.cache_read_per_mtok;
    let cache_creation_cost =
        (cache_creation_tokens.unwrap_or(0) as f64 / 1_000_000.0) * pricing.cache_creation_per_mtok;
    Some(input_cost + output_cost + cache_read_cost + cache_creation_cost)
}

/// Parse a raw Claude API usage block into a `ParsedUsage`.
pub fn parse_api_usage(
    raw: &RawTokenUsage,
    agent_id: &str,
    session_id: Option<i64>,
    model: &str,
) -> ParsedUsage {
    let cost = estimate_cost(
        model,
        raw.input_tokens,
        raw.output_tokens,
        raw.cache_read_input_tokens,
        raw.cache_creation_input_tokens,
    );
    ParsedUsage {
        agent_id: agent_id.to_string(),
        session_id,
        input_tokens: raw.input_tokens,
        output_tokens: raw.output_tokens,
        cache_read_tokens: raw.cache_read_input_tokens,
        cache_creation_tokens: raw.cache_creation_input_tokens,
        model: model.to_string(),
        cost_estimate: cost,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_estimate_cost_sonnet() {
        let cost = estimate_cost("claude-sonnet-4-20250514", 1_000_000, 1_000_000, None, None);
        assert!(cost.is_some());
        let c = cost.unwrap();
        // 3.0 + 15.0 = 18.0
        assert!((c - 18.0).abs() < 0.001);
    }

    #[test]
    fn test_estimate_cost_opus() {
        let cost = estimate_cost("claude-opus-4-20250514", 1_000_000, 1_000_000, None, None);
        assert!(cost.is_some());
        let c = cost.unwrap();
        // 15.0 + 75.0 = 90.0
        assert!((c - 90.0).abs() < 0.001);
    }

    #[test]
    fn test_estimate_cost_haiku() {
        let cost = estimate_cost(
            "claude-haiku-4-5-20251001",
            1_000_000,
            1_000_000,
            None,
            None,
        );
        assert!(cost.is_some());
        let c = cost.unwrap();
        // 0.80 + 4.0 = 4.80
        assert!((c - 4.80).abs() < 0.001);
    }

    #[test]
    fn test_estimate_cost_with_cache() {
        let cost = estimate_cost(
            "claude-sonnet-4-20250514",
            500_000,
            200_000,
            Some(1_000_000),
            Some(300_000),
        );
        assert!(cost.is_some());
        let c = cost.unwrap();
        // input: 0.5 * 3.0 = 1.5
        // output: 0.2 * 15.0 = 3.0
        // cache_read: 1.0 * 0.3 = 0.3
        // cache_creation: 0.3 * 3.75 = 1.125
        let expected = 1.5 + 3.0 + 0.3 + 1.125;
        assert!((c - expected).abs() < 0.001);
    }

    #[test]
    fn test_estimate_cost_unknown_model() {
        let cost = estimate_cost("gpt-4o", 1000, 500, None, None);
        assert!(cost.is_none());
    }

    #[test]
    fn test_parse_api_usage() {
        let raw = RawTokenUsage {
            input_tokens: 5000,
            output_tokens: 1000,
            cache_read_input_tokens: Some(10000),
            cache_creation_input_tokens: None,
        };
        let parsed = parse_api_usage(&raw, "agent-1", Some(42), "claude-sonnet-4-20250514");
        assert_eq!(parsed.agent_id, "agent-1");
        assert_eq!(parsed.session_id, Some(42));
        assert_eq!(parsed.input_tokens, 5000);
        assert_eq!(parsed.output_tokens, 1000);
        assert_eq!(parsed.cache_read_tokens, Some(10000));
        assert!(parsed.cost_estimate.is_some());
        assert_eq!(parsed.model, "claude-sonnet-4-20250514");
    }

    #[test]
    fn test_raw_token_usage_deserialize() {
        let json = r#"{"input_tokens": 100, "output_tokens": 50}"#;
        let raw: RawTokenUsage = serde_json::from_str(json).unwrap();
        assert_eq!(raw.input_tokens, 100);
        assert_eq!(raw.output_tokens, 50);
        assert!(raw.cache_read_input_tokens.is_none());
    }

    #[test]
    fn test_raw_token_usage_deserialize_with_cache() {
        let json = r#"{
            "input_tokens": 100,
            "output_tokens": 50,
            "cache_read_input_tokens": 2000,
            "cache_creation_input_tokens": 500
        }"#;
        let raw: RawTokenUsage = serde_json::from_str(json).unwrap();
        assert_eq!(raw.cache_read_input_tokens, Some(2000));
        assert_eq!(raw.cache_creation_input_tokens, Some(500));
    }
}

use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::path::Path;

/// Trust model configuration, loaded from `.crosslink/swarm.toml`
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct TrustConfig {
    #[serde(default)]
    pub trust: TrustProfile,
    #[serde(default)]
    pub ignore: IgnoreRules,
    #[serde(default)]
    pub boundaries: BoundaryConfig,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TrustProfile {
    /// Trust model type: "local-only", "multi-tenant", "public-api", "custom"
    #[serde(default = "default_model")]
    pub model: String,
    /// Description of the trust model for agent context
    #[serde(default)]
    pub description: String,
}

fn default_model() -> String {
    "local-only".to_string()
}

impl Default for TrustProfile {
    fn default() -> Self {
        Self {
            model: default_model(),
            description: String::new(),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct IgnoreRules {
    /// Patterns to match against finding titles — matched findings get "by-design" annotation
    #[serde(default)]
    pub patterns: Vec<String>,
    /// Reason shown when a finding is triaged as by-design
    #[serde(default)]
    pub reason: String,
}

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct BoundaryConfig {
    /// External interfaces: "http", "ws", "grpc", "cli", "file"
    #[serde(default)]
    pub external: Vec<String>,
    /// Internal/trusted interfaces
    #[serde(default)]
    pub internal: Vec<String>,
}

/// Result of applying trust model to a finding
#[derive(Debug, Clone, PartialEq)]
pub enum TriageResult {
    /// Finding is valid and should be reported
    Valid,
    /// Finding is by-design per trust model
    ByDesign { reason: String },
    /// Finding severity should be adjusted
    Downgraded {
        original_severity: String,
        new_severity: String,
        reason: String,
    },
}

/// Load trust configuration from `.crosslink/swarm.toml`.
///
/// Returns a default configuration if the file does not exist.
pub fn load_trust_config(crosslink_dir: &Path) -> Result<TrustConfig> {
    let config_path = crosslink_dir.join("swarm.toml");
    if !config_path.exists() {
        return Ok(TrustConfig::default());
    }
    let contents = std::fs::read_to_string(&config_path)
        .with_context(|| format!("failed to read {}", config_path.display()))?;
    let config: TrustConfig =
        toml::from_str(&contents).with_context(|| "failed to parse swarm.toml")?;
    Ok(config)
}

/// Check if a finding matches any ignore pattern (case-insensitive substring match).
///
/// Returns `ByDesign` if the finding title matches an ignore pattern, `Valid` otherwise.
pub fn triage_finding(config: &TrustConfig, title: &str, description: &str) -> TriageResult {
    let title_lower = title.to_lowercase();
    let description_lower = description.to_lowercase();

    // Check ignore patterns — matched findings are triaged as by-design.
    for pattern in &config.ignore.patterns {
        if title_lower.contains(&pattern.to_lowercase()) {
            return TriageResult::ByDesign {
                reason: if config.ignore.reason.is_empty() {
                    format!("matched ignore pattern: {}", pattern)
                } else {
                    config.ignore.reason.clone()
                },
            };
        }
    }

    // Check boundary-based downgrade — findings about internal boundaries get
    // severity reduced because internal interfaces have implicit trust.
    for boundary in &config.boundaries.internal {
        let boundary_lower = boundary.to_lowercase();
        if title_lower.contains(&boundary_lower) || description_lower.contains(&boundary_lower) {
            return TriageResult::Downgraded {
                original_severity: "high".to_string(),
                new_severity: "low".to_string(),
                reason: format!(
                    "finding relates to internal boundary '{}' which has implicit trust",
                    boundary
                ),
            };
        }
    }

    TriageResult::Valid
}

/// Apply triage to a list of findings.
///
/// Each finding is a `(title, description, severity)` tuple. Returns each finding
/// annotated with its `TriageResult`. Findings are never silently dropped.
pub fn apply_trust_model(
    config: &TrustConfig,
    findings: Vec<(String, String, String)>,
) -> Vec<(String, String, String, TriageResult)> {
    findings
        .into_iter()
        .map(|(title, description, severity)| {
            let result = triage_finding(config, &title, &description);
            (title, description, severity, result)
        })
        .collect()
}

/// Generate a sensible default config for common trust models.
pub fn generate_default_config(model: &str) -> TrustConfig {
    match model {
        "local-only" => TrustConfig {
            trust: TrustProfile {
                model: "local-only".to_string(),
                description: "Single-user local tool — no network auth required".to_string(),
            },
            ignore: IgnoreRules {
                patterns: vec![
                    "authentication".to_string(),
                    "authorization".to_string(),
                    "session management".to_string(),
                ],
                reason: "Local-only tool with no network exposure".to_string(),
            },
            boundaries: BoundaryConfig {
                external: vec!["cli".to_string(), "file".to_string()],
                internal: vec![],
            },
        },
        "multi-tenant" => TrustConfig {
            trust: TrustProfile {
                model: "multi-tenant".to_string(),
                description: "Multi-tenant service with tenant isolation requirements".to_string(),
            },
            ignore: IgnoreRules::default(),
            boundaries: BoundaryConfig {
                external: vec!["http".to_string(), "ws".to_string(), "grpc".to_string()],
                internal: vec![],
            },
        },
        "public-api" => TrustConfig {
            trust: TrustProfile {
                model: "public-api".to_string(),
                description: "Public-facing API with untrusted input".to_string(),
            },
            ignore: IgnoreRules::default(),
            boundaries: BoundaryConfig {
                external: vec!["http".to_string(), "ws".to_string()],
                internal: vec![],
            },
        },
        _ => TrustConfig {
            trust: TrustProfile {
                model: model.to_string(),
                description: String::new(),
            },
            ignore: IgnoreRules::default(),
            boundaries: BoundaryConfig::default(),
        },
    }
}

/// Write a default `swarm.toml` configuration for the given trust model.
pub fn write_default_config(crosslink_dir: &Path, model: &str) -> Result<()> {
    let config = generate_default_config(model);
    let contents =
        toml::to_string_pretty(&config).with_context(|| "failed to serialize trust config")?;
    let config_path = crosslink_dir.join("swarm.toml");
    std::fs::write(&config_path, contents)
        .with_context(|| format!("failed to write {}", config_path.display()))?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn load_returns_default_when_file_missing() {
        let dir = TempDir::new().unwrap();
        let config = load_trust_config(dir.path()).unwrap();
        assert_eq!(config.trust.model, "local-only");
        assert!(config.ignore.patterns.is_empty());
        assert!(config.boundaries.external.is_empty());
    }

    #[test]
    fn load_parses_valid_toml() {
        let dir = TempDir::new().unwrap();
        let toml_content = r#"
[trust]
model = "multi-tenant"
description = "My service"

[ignore]
patterns = ["authentication", "CSRF"]
reason = "Handled by gateway"

[boundaries]
external = ["http", "grpc"]
internal = ["db"]
"#;
        std::fs::write(dir.path().join("swarm.toml"), toml_content).unwrap();
        let config = load_trust_config(dir.path()).unwrap();
        assert_eq!(config.trust.model, "multi-tenant");
        assert_eq!(config.trust.description, "My service");
        assert_eq!(config.ignore.patterns.len(), 2);
        assert_eq!(config.ignore.reason, "Handled by gateway");
        assert_eq!(config.boundaries.external, vec!["http", "grpc"]);
        assert_eq!(config.boundaries.internal, vec!["db"]);
    }

    #[test]
    fn triage_finding_matches_patterns_case_insensitively() {
        let config = TrustConfig {
            ignore: IgnoreRules {
                patterns: vec!["Authentication".to_string()],
                reason: "Not applicable".to_string(),
            },
            ..Default::default()
        };
        let result = triage_finding(&config, "Missing AUTHENTICATION check", "details");
        assert_eq!(
            result,
            TriageResult::ByDesign {
                reason: "Not applicable".to_string()
            }
        );
    }

    #[test]
    fn triage_finding_returns_valid_when_no_patterns_match() {
        let config = TrustConfig {
            ignore: IgnoreRules {
                patterns: vec!["authentication".to_string()],
                reason: "Not applicable".to_string(),
            },
            ..Default::default()
        };
        let result = triage_finding(&config, "SQL injection in query builder", "details");
        assert_eq!(result, TriageResult::Valid);
    }

    #[test]
    fn generate_default_config_local_only() {
        let config = generate_default_config("local-only");
        assert_eq!(config.trust.model, "local-only");
        assert!(!config.ignore.patterns.is_empty());
        assert!(config
            .ignore
            .patterns
            .contains(&"authentication".to_string()));
        assert!(config
            .ignore
            .patterns
            .contains(&"authorization".to_string()));
        assert_eq!(
            config.boundaries.external,
            vec!["cli".to_string(), "file".to_string()]
        );
    }

    #[test]
    fn generate_default_config_multi_tenant() {
        let config = generate_default_config("multi-tenant");
        assert_eq!(config.trust.model, "multi-tenant");
        assert!(config.ignore.patterns.is_empty());
        assert_eq!(
            config.boundaries.external,
            vec!["http".to_string(), "ws".to_string(), "grpc".to_string()]
        );
    }

    #[test]
    fn generate_default_config_public_api() {
        let config = generate_default_config("public-api");
        assert_eq!(config.trust.model, "public-api");
        assert!(config.ignore.patterns.is_empty());
        assert_eq!(
            config.boundaries.external,
            vec!["http".to_string(), "ws".to_string()]
        );
    }

    #[test]
    fn serde_roundtrip_toml() {
        let config = generate_default_config("local-only");
        let serialized = toml::to_string_pretty(&config).unwrap();
        let deserialized: TrustConfig = toml::from_str(&serialized).unwrap();
        assert_eq!(deserialized.trust.model, config.trust.model);
        assert_eq!(deserialized.trust.description, config.trust.description);
        assert_eq!(deserialized.ignore.patterns, config.ignore.patterns);
        assert_eq!(deserialized.ignore.reason, config.ignore.reason);
        assert_eq!(deserialized.boundaries.external, config.boundaries.external);
        assert_eq!(deserialized.boundaries.internal, config.boundaries.internal);
    }

    #[test]
    fn by_design_includes_configured_reason() {
        let config = TrustConfig {
            ignore: IgnoreRules {
                patterns: vec!["auth".to_string()],
                reason: "Local-only tool with no network exposure".to_string(),
            },
            ..Default::default()
        };
        let result = triage_finding(&config, "Missing auth middleware", "desc");
        match result {
            TriageResult::ByDesign { reason } => {
                assert_eq!(reason, "Local-only tool with no network exposure");
            }
            other => panic!("Expected ByDesign, got {:?}", other),
        }
    }

    #[test]
    fn by_design_uses_default_reason_when_empty() {
        let config = TrustConfig {
            ignore: IgnoreRules {
                patterns: vec!["auth".to_string()],
                reason: String::new(),
            },
            ..Default::default()
        };
        let result = triage_finding(&config, "Missing auth middleware", "desc");
        match result {
            TriageResult::ByDesign { reason } => {
                assert!(reason.contains("matched ignore pattern"));
                assert!(reason.contains("auth"));
            }
            other => panic!("Expected ByDesign, got {:?}", other),
        }
    }

    #[test]
    fn apply_trust_model_annotates_all_findings() {
        let config = TrustConfig {
            ignore: IgnoreRules {
                patterns: vec!["authentication".to_string()],
                reason: "Not applicable".to_string(),
            },
            ..Default::default()
        };
        let findings = vec![
            (
                "Missing authentication".to_string(),
                "desc1".to_string(),
                "high".to_string(),
            ),
            (
                "SQL injection".to_string(),
                "desc2".to_string(),
                "critical".to_string(),
            ),
        ];
        let results = apply_trust_model(&config, findings);
        assert_eq!(results.len(), 2);
        assert_eq!(
            results[0].3,
            TriageResult::ByDesign {
                reason: "Not applicable".to_string()
            }
        );
        assert_eq!(results[1].3, TriageResult::Valid);
    }

    #[test]
    fn write_and_load_roundtrip() {
        let dir = TempDir::new().unwrap();
        write_default_config(dir.path(), "multi-tenant").unwrap();
        let loaded = load_trust_config(dir.path()).unwrap();
        assert_eq!(loaded.trust.model, "multi-tenant");
        assert!(loaded.trust.description.contains("Multi-tenant"));
    }

    #[test]
    fn triage_finding_downgrades_internal_boundary_in_title() {
        let config = TrustConfig {
            boundaries: BoundaryConfig {
                internal: vec!["internal-db".to_string()],
                ..Default::default()
            },
            ..Default::default()
        };
        let result = triage_finding(&config, "SQL injection via internal-db", "some details");
        match result {
            TriageResult::Downgraded {
                original_severity,
                new_severity,
                reason,
            } => {
                assert_eq!(original_severity, "high");
                assert_eq!(new_severity, "low");
                assert!(reason.contains("internal-db"));
                assert!(reason.contains("implicit trust"));
            }
            other => panic!("Expected Downgraded, got {:?}", other),
        }
    }

    #[test]
    fn triage_finding_downgrades_internal_boundary_in_description() {
        let config = TrustConfig {
            boundaries: BoundaryConfig {
                internal: vec!["message-bus".to_string()],
                ..Default::default()
            },
            ..Default::default()
        };
        // Pattern only in description, not title
        let result = triage_finding(&config, "Unvalidated input", "goes through message-bus");
        match result {
            TriageResult::Downgraded { .. } => {}
            other => panic!("Expected Downgraded, got {:?}", other),
        }
    }

    #[test]
    fn generate_default_config_custom_model() {
        let config = generate_default_config("my-custom-model");
        assert_eq!(config.trust.model, "my-custom-model");
        assert!(config.trust.description.is_empty());
        assert!(config.ignore.patterns.is_empty());
        assert!(config.boundaries.external.is_empty());
        assert!(config.boundaries.internal.is_empty());
    }
}

use crossterm::event::{KeyCode, KeyEvent};
use ratatui::{
    layout::{Constraint, Direction, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Row, Table, TableState, Wrap},
    Frame,
};
use std::cell::RefCell;
use std::path::{Path, PathBuf};
use std::sync::mpsc;

use super::{Tab, TabAction};

/// Background color for highlighted/selected rows (256-color palette, dark gray).
const HIGHLIGHT_BG: Color = Color::Indexed(236);

use crate::events;
use crate::locks::{Heartbeat, Lock, LocksFile};
use crate::signing::AllowedSignerEntry;
use crate::sync::SyncManager;

/// Which sub-view is active within the Agents tab.
#[derive(Clone, Copy, Debug, PartialEq)]
enum ViewMode {
    /// Main view: merged agent activity table.
    Agents,
    /// Lock-focused view: all locks + stale detection.
    Locks,
    /// Trust store view: allowed signers list.
    Trust,
    /// Detail view for a specific agent.
    Detail,
}

/// A row in the merged agents table.
struct AgentRow {
    agent_id: String,
    active_issue: Option<i64>,
    lock_issue: Option<i64>,
    branch: Option<String>,
    heartbeat_ago: Option<String>,
    is_stale: bool,
    machine_id: Option<String>,
}

/// A row in the locks table.
struct LockRow {
    issue_id: i64,
    agent_id: String,
    branch: Option<String>,
    claimed_ago: String,
    is_stale: bool,
}

/// Detail for a selected agent.
struct AgentDetail {
    agent_id: String,
    machine_id: Option<String>,
    heartbeat: Option<Heartbeat>,
    locks: Vec<(i64, Lock)>,
    recent_events: Vec<events::EventEnvelope>,
    is_stale: bool,
}

/// Data payload sent from background refresh thread.
struct AgentsLoadResult {
    agents: Vec<AgentRow>,
    lock_rows: Vec<LockRow>,
    trust_entries: Vec<AllowedSignerEntry>,
    status_msg: String,
    error_msg: Option<String>,
}

/// The Agents tab — live coordination dashboard.
pub struct AgentsTab {
    crosslink_dir: PathBuf,
    view_mode: ViewMode,
    /// Merged agent rows (agents view).
    agents: Vec<AgentRow>,
    selected: usize,
    /// Lock rows (locks view).
    lock_rows: Vec<LockRow>,
    lock_selected: usize,
    /// Trust entries (trust view).
    trust_entries: Vec<AllowedSignerEntry>,
    trust_selected: usize,
    /// Detail for a specific agent.
    detail: Option<AgentDetail>,
    detail_scroll: usize,
    /// Status message (e.g. "Last sync: 12s ago").
    status_msg: String,
    /// Error message if data load failed.
    error_msg: Option<String>,
    /// Whether a background load is in progress.
    loading: bool,
    /// Receiver for background load results.
    load_rx: Option<mpsc::Receiver<AgentsLoadResult>>,
    /// TableState for agents view scroll-to-follow.
    agents_table_state: RefCell<TableState>,
    /// TableState for locks view scroll-to-follow.
    locks_table_state: RefCell<TableState>,
    /// TableState for trust view scroll-to-follow.
    trust_table_state: RefCell<TableState>,
}

impl AgentsTab {
    pub fn new(crosslink_dir: &Path) -> Self {
        let mut tab = AgentsTab {
            crosslink_dir: crosslink_dir.to_path_buf(),
            view_mode: ViewMode::Agents,
            agents: Vec::new(),
            selected: 0,
            lock_rows: Vec::new(),
            lock_selected: 0,
            trust_entries: Vec::new(),
            trust_selected: 0,
            detail: None,
            detail_scroll: 0,
            status_msg: String::new(),
            error_msg: None,
            loading: false,
            load_rx: None,
            agents_table_state: RefCell::new(TableState::default()),
            locks_table_state: RefCell::new(TableState::default()),
            trust_table_state: RefCell::new(TableState::default()),
        };
        tab.start_background_refresh();
        tab
    }

    /// Spawn a background thread to load agents/locks/trust data without blocking the UI.
    fn start_background_refresh(&mut self) {
        self.loading = true;
        let (tx, rx) = mpsc::channel();
        self.load_rx = Some(rx);
        let crosslink_dir = self.crosslink_dir.clone();

        std::thread::spawn(move || {
            let result = load_agents_data(&crosslink_dir);
            let _ = tx.send(result);
        });
    }

    /// Apply a completed background load result to the tab state.
    fn apply_load_result(&mut self, result: AgentsLoadResult) {
        self.loading = false;
        self.agents = result.agents;
        self.lock_rows = result.lock_rows;
        self.trust_entries = result.trust_entries;
        self.status_msg = result.status_msg;
        self.error_msg = result.error_msg;

        // Clamp selections
        if self.selected >= self.agents.len() && !self.agents.is_empty() {
            self.selected = self.agents.len() - 1;
        }
        if self.lock_selected >= self.lock_rows.len() && !self.lock_rows.is_empty() {
            self.lock_selected = self.lock_rows.len() - 1;
        }
        if self.trust_selected >= self.trust_entries.len() && !self.trust_entries.is_empty() {
            self.trust_selected = self.trust_entries.len() - 1;
        }
    }

    fn load_detail(&mut self, agent_id: &str) {
        let sync = match SyncManager::new(&self.crosslink_dir) {
            Ok(s) => s,
            Err(_) => return,
        };

        // Find heartbeat for this agent
        let heartbeats = sync.read_heartbeats().unwrap_or_default();
        let heartbeat = heartbeats.into_iter().find(|h| h.agent_id == agent_id);

        // Find locks held by this agent
        let locks = sync
            .read_locks_auto()
            .unwrap_or_else(|_| LocksFile::empty());
        let agent_locks: Vec<(i64, Lock)> = locks
            .locks
            .into_iter()
            .filter(|(_, lock)| lock.agent_id == agent_id)
            .map(|(id_str, lock)| (id_str.parse::<i64>().unwrap_or(0), lock))
            .collect();

        // Read recent events for this agent
        let events_path = sync
            .cache_path()
            .join("agents")
            .join(agent_id)
            .join("events.log");
        let all_events = events::read_events(&events_path).unwrap_or_default();
        // Take last 20 events
        let recent_events: Vec<events::EventEnvelope> =
            all_events.into_iter().rev().take(20).collect();

        // Check stale status
        let stale = sync.find_stale_locks().unwrap_or_default();
        let is_stale = stale.iter().any(|(_, a)| a == agent_id);

        let machine_id = heartbeat.as_ref().map(|h| h.machine_id.clone());

        self.detail = Some(AgentDetail {
            agent_id: agent_id.to_string(),
            machine_id,
            heartbeat,
            locks: agent_locks,
            recent_events,
            is_stale,
        });
        self.detail_scroll = 0;
    }

    // ── Key handlers ──────────────────────────────────────────────────

    fn handle_agents_key(&mut self, key: KeyEvent) -> TabAction {
        match key.code {
            KeyCode::Char('j') | KeyCode::Down => {
                if !self.agents.is_empty() {
                    self.selected = (self.selected + 1).min(self.agents.len() - 1);
                }
                TabAction::Consumed
            }
            KeyCode::Char('k') | KeyCode::Up => {
                self.selected = self.selected.saturating_sub(1);
                TabAction::Consumed
            }
            KeyCode::Enter => {
                if let Some(agent) = self.agents.get(self.selected) {
                    let agent_id = agent.agent_id.clone();
                    self.load_detail(&agent_id);
                    self.view_mode = ViewMode::Detail;
                }
                TabAction::Consumed
            }
            KeyCode::Char('v') => {
                self.view_mode = ViewMode::Locks;
                TabAction::Consumed
            }
            KeyCode::Char('r') => TabAction::NotHandled,
            _ => TabAction::NotHandled,
        }
    }

    fn handle_locks_key(&mut self, key: KeyEvent) -> TabAction {
        match key.code {
            KeyCode::Char('j') | KeyCode::Down => {
                if !self.lock_rows.is_empty() {
                    self.lock_selected = (self.lock_selected + 1).min(self.lock_rows.len() - 1);
                }
                TabAction::Consumed
            }
            KeyCode::Char('k') | KeyCode::Up => {
                self.lock_selected = self.lock_selected.saturating_sub(1);
                TabAction::Consumed
            }
            KeyCode::Char('v') => {
                self.view_mode = ViewMode::Trust;
                TabAction::Consumed
            }
            KeyCode::Char('r') => TabAction::NotHandled,
            KeyCode::Esc => {
                self.view_mode = ViewMode::Agents;
                TabAction::Consumed
            }
            _ => TabAction::NotHandled,
        }
    }

    fn handle_trust_key(&mut self, key: KeyEvent) -> TabAction {
        match key.code {
            KeyCode::Char('j') | KeyCode::Down => {
                if !self.trust_entries.is_empty() {
                    self.trust_selected =
                        (self.trust_selected + 1).min(self.trust_entries.len() - 1);
                }
                TabAction::Consumed
            }
            KeyCode::Char('k') | KeyCode::Up => {
                self.trust_selected = self.trust_selected.saturating_sub(1);
                TabAction::Consumed
            }
            KeyCode::Char('v') => {
                self.view_mode = ViewMode::Agents;
                TabAction::Consumed
            }
            KeyCode::Char('r') => TabAction::NotHandled,
            KeyCode::Esc => {
                self.view_mode = ViewMode::Agents;
                TabAction::Consumed
            }
            _ => TabAction::NotHandled,
        }
    }

    fn handle_detail_key(&mut self, key: KeyEvent) -> TabAction {
        match key.code {
            KeyCode::Esc => {
                self.view_mode = ViewMode::Agents;
                self.detail = None;
                TabAction::Consumed
            }
            KeyCode::Char('j') | KeyCode::Down => {
                self.detail_scroll = self.detail_scroll.saturating_add(1);
                TabAction::Consumed
            }
            KeyCode::Char('k') | KeyCode::Up => {
                self.detail_scroll = self.detail_scroll.saturating_sub(1);
                TabAction::Consumed
            }
            KeyCode::PageDown => {
                self.detail_scroll = self.detail_scroll.saturating_add(10);
                TabAction::Consumed
            }
            KeyCode::PageUp => {
                self.detail_scroll = self.detail_scroll.saturating_sub(10);
                TabAction::Consumed
            }
            _ => TabAction::NotHandled,
        }
    }

    // ── Renderers ─────────────────────────────────────────────────────

    fn render_agents(&self, frame: &mut Frame, area: Rect) {
        let chunks = Layout::default()
            .direction(Direction::Vertical)
            .constraints([
                Constraint::Length(1), // Header
                Constraint::Min(0),    // Table
                Constraint::Length(1), // Context keys
            ])
            .split(area);

        // Header
        let header = Line::from(vec![
            Span::styled(
                " Agents & Locks",
                Style::default()
                    .fg(Color::Cyan)
                    .add_modifier(Modifier::BOLD),
            ),
            Span::styled(
                format!("  {}", self.status_msg),
                Style::default().fg(Color::DarkGray),
            ),
        ]);
        frame.render_widget(Paragraph::new(header), chunks[0]);

        // Error or empty state
        if let Some(ref err) = self.error_msg {
            let msg = Paragraph::new(Line::from(vec![
                Span::raw("  "),
                Span::styled(err, Style::default().fg(Color::Red)),
            ]));
            frame.render_widget(msg, chunks[1]);
            return;
        }

        if self.loading && self.agents.is_empty() {
            let msg = Paragraph::new(Line::from(Span::styled(
                "  Loading agents...",
                Style::default().fg(Color::DarkGray),
            )));
            frame.render_widget(msg, chunks[1]);
        } else if self.agents.is_empty() {
            let msg = Paragraph::new(Line::from(Span::styled(
                "  No agents detected. Hub may not be initialized.",
                Style::default().fg(Color::DarkGray),
            )));
            frame.render_widget(msg, chunks[1]);
        } else {
            // Table
            let header_row = Row::new(vec!["Agent", "Active", "Lock", "Branch", "Heartbeat"])
                .style(
                    Style::default()
